{
  "name": "PIPA Voice AI",
  "description": "Sistema de Gestão de Fluência Leitora com Inteligência Artificial para análise pedagógica.",
  "requestFramePermissions": [
    "microphone"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Student {
  id: number;
  name: string;
  ppm: number;
  status: 'Nível 1' | 'Iniciante' | 'Fluente';
  report: string;
}

export interface Metrics {
  words: number;
  time: number;
  ppm: number;
}

// Minimal type definitions for Web Speech API since it's not fully standard in all TS configs
export interface IWindow extends Window {
  webkitSpeechRecognition: any;
  SpeechRecognition: any;
}

export type RecordingState = 'idle' | 'recording' | 'analyzing';

import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const analyzeReadingFluency = async (
  transcript: string, 
  ppm: number
): Promise<string> => {
  try {
    const prompt = `
      Analise a fluência leitora desta criança baseada na seguinte transcrição de leitura em voz alta.

      Dados quantitativos:
      - PPM (Palavras Por Minuto): ${ppm}

      Transcrição: "${transcript}"

      Por favor, forneça:
      1. Uma breve avaliação da precisão.
      2. Uma observação sobre a prosódia (baseada na pontuação e fluidez do texto transcrito).
      3. Uma conclusão pedagógica curta e acionável.

      Mantenha a resposta concisa (máximo de 3 parágrafos curtos).
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });

    return response.text || "Não foi possível gerar a análise.";
  } catch (error) {
    console.error("Error analyzing fluency:", error);
    return "Erro ao conectar com a IA. Verifique sua conexão ou tente novamente.";
  }
};

import React from 'react';
import { PieChart, Pie, Cell, Tooltip, ResponsiveContainer, Legend } from 'recharts';
import { Student } from '../types';

interface FluencyChartProps {
  students: Student[];
}

const FluencyChart: React.FC<FluencyChartProps> = ({ students }) => {
  const evaluatedStudents = students.filter(s => s.ppm > 0);

  if (evaluatedStudents.length === 0) {
     const emptyData = [
        { name: 'Sem dados', value: 1 }
     ];
     return (
        <div className="h-48 w-full flex items-center justify-center text-slate-400 text-xs uppercase tracking-widest">
           Nenhum aluno avaliado
        </div>
     );
  }

  const fluentCount = evaluatedStudents.filter(s => s.status === 'Fluente').length;
  const beginnerCount = evaluatedStudents.filter(s => s.status !== 'Fluente').length;

  const data = [
    { name: 'Fluente', value: fluentCount },
    { name: 'Iniciante', value: beginnerCount },
  ];

  const COLORS = ['#10b981', '#f43f5e']; // Emerald-500, Rose-500

  return (
    <div className="h-64 w-full">
      <ResponsiveContainer width="100%" height="100%">
        <PieChart>
          <Pie
            data={data}
            cx="50%"
            cy="50%"
            innerRadius={60}
            outerRadius={80}
            paddingAngle={5}
            dataKey="value"
          >
            {data.map((entry, index) => (
              <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
            ))}
          </Pie>
          <Tooltip 
            contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px rgba(0,0,0,0.1)' }}
            itemStyle={{ fontSize: '12px', fontWeight: 'bold' }}
          />
          <Legend 
            verticalAlign="bottom" 
            height={36} 
            iconType="circle"
            wrapperStyle={{ fontSize: '10px', fontWeight: 'bold', textTransform: 'uppercase' }}
          />
        </PieChart>
      </ResponsiveContainer>
    </div>
  );
};

export default FluencyChart;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Student, Metrics, RecordingState, IWindow } from './types';
import { analyzeReadingFluency } from './services/geminiService';
import FluencyChart from './components/FluencyChart';
import { Plus, Mic, Square, Activity, Save, Trash2, BookOpen } from 'lucide-react';

const App: React.FC = () => {
  // --- State ---
  const [students, setStudents] = useState<Student[]>([
    { id: 1, name: "AGATHA MAMEDE", ppm: 0, status: "Nível 1", report: "" },
    { id: 2, name: "MURILLO FELIX", ppm: 0, status: "Nível 1", report: "" }
  ]);
  const [activeStudentId, setActiveStudentId] = useState<number | null>(null);
  const [recordingState, setRecordingState] = useState<RecordingState>('idle');
  const [transcript, setTranscript] = useState<string>("");
  const [startTime, setStartTime] = useState<number>(0);
  const [liveMetrics, setLiveMetrics] = useState<Metrics>({ words: 0, time: 0, ppm: 0 });
  const [schoolName, setSchoolName] = useState<string>("");
  const [className, setClassName] = useState<string>("");

  // --- Refs ---
  const recognitionRef = useRef<any>(null);
  const timerIntervalRef = useRef<NodeJS.Timeout | null>(null);

  // --- Helpers ---
  const updateLiveMetrics = useCallback(() => {
    if (!startTime) return;
    const now = Date.now();
    const seconds = Math.max(1, Math.floor((now - startTime) / 1000));

    // Simple word count by splitting spaces
    const currentTranscript = transcript.trim();
    const wordCount = currentTranscript ? currentTranscript.split(/\s+/).length : 0;

    const ppm = Math.round((wordCount / seconds) * 60);

    setLiveMetrics({
      words: wordCount,
      time: seconds,
      ppm: ppm
    });
  }, [transcript, startTime]);

  // Update metrics whenever transcript changes during recording
  useEffect(() => {
    if (recordingState === 'recording') {
      updateLiveMetrics();
    }
  }, [transcript, recordingState, updateLiveMetrics]);

  // Timer effect
  useEffect(() => {
    if (recordingState === 'recording') {
      timerIntervalRef.current = setInterval(() => {
        updateLiveMetrics();
      }, 1000);
    } else {
      if (timerIntervalRef.current) clearInterval(timerIntervalRef.current);
    }
    return () => {
      if (timerIntervalRef.current) clearInterval(timerIntervalRef.current);
    };
  }, [recordingState, updateLiveMetrics]);

  // --- Handlers ---

  const handleStartRecording = (id: number) => {
    if (activeStudentId !== null && activeStudentId !== id) {
      alert("Por favor, finalize a gravação atual antes de iniciar outra.");
      return;
    }

    const w = window as unknown as IWindow;
    const SpeechRecognition = w.SpeechRecognition || w.webkitSpeechRecognition;

    if (!SpeechRecognition) {
      alert("Seu navegador não suporta reconhecimento de fala via Web Speech API.");
      return;
    }

    const recognition = new SpeechRecognition();
    recognition.continuous = true;
    recognition.interimResults = true;
    recognition.lang = 'pt-BR';

    recognition.onresult = (event: any) => {
      let finalTrans = '';
      let interimTrans = '';

      for (let i = event.resultIndex; i < event.results.length; ++i) {
        if (event.results[i].isFinal) {
          finalTrans += event.results[i][0].transcript;
        } else {
          interimTrans += event.results[i][0].transcript;
        }
      }

      // We append final results to existing transcript state if needed, 
      // but for simplicity in this demo, we often just want the cumulative text.
      // However, the event returns everything since start in some impls, 
      // or just new chunks. Let's accumulate carefully.
      // Standard Web Speech API structure: results list grows.

      // A safer way for React state:
      let fullTranscript = '';
      for (let i = 0; i < event.results.length; ++i) {
         fullTranscript += event.results[i][0].transcript;
      }
      setTranscript(fullTranscript);
    };

    recognition.onerror = (event: any) => {
      console.error("Speech recognition error", event.error);
    };

    recognition.start();
    recognitionRef.current = recognition;

    setActiveStudentId(id);
    setRecordingState('recording');
    setStartTime(Date.now());
    setTranscript("");
    setLiveMetrics({ words: 0, time: 0, ppm: 0 });
  };

  const handleStopRecording = async () => {
    if (recognitionRef.current) {
      recognitionRef.current.stop();
    }
    setRecordingState('analyzing');

    // Analyze with Gemini
    if (activeStudentId !== null) {
      const result = await analyzeReadingFluency(transcript, liveMetrics.ppm);

      setStudents(prev => prev.map(s => {
        if (s.id === activeStudentId) {
          return {
            ...s,
            ppm: liveMetrics.ppm,
            status: liveMetrics.ppm > 60 ? 'Fluente' : 'Iniciante',
            report: result
          };
        }
        return s;
      }));
    }

    setRecordingState('idle');
    setActiveStudentId(null);
  };

  const addStudent = () => {
    const newId = Date.now();
    setStudents([...students, { id: newId, name: "NOVO ALUNO", ppm: 0, status: "Nível 1", report: "" }]);
  };

  const updateStudentName = (id: number, newName: string) => {
    setStudents(students.map(s => s.id === id ? { ...s, name: newName } : s));
  };

  const removeStudent = (id: number) => {
      if (confirm('Tem certeza que deseja remover este aluno?')) {
          setStudents(students.filter(s => s.id !== id));
      }
  };

  // --- Stats Calculation ---
  const evaluatedCount = students.filter(s => s.ppm > 0).length;
  const totalStudents = students.length;
  const avgPpm = evaluatedCount > 0 
    ? students.reduce((acc, s) => acc + s.ppm, 0) / evaluatedCount 
    : 0;

  // --- Render ---
  return (
    <div className="min-h-screen bg-slate-50 font-sans text-slate-900 pb-12">
      {/* Header */}
      <header className="bg-slate-900 text-white shadow-xl mb-8 relative overflow-hidden">
        {/* Decorative background element */}
        <div className="absolute top-0 right-0 w-64 h-64 bg-blue-500 rounded-full mix-blend-multiply filter blur-3xl opacity-10 animate-blob"></div>
        <div className="absolute top-0 left-0 w-64 h-64 bg-purple-500 rounded-full mix-blend-multiply filter blur-3xl opacity-10 animate-blob animation-delay-2000"></div>

        <div className="container mx-auto p-6 relative z-10">
          <div className="flex flex-col md:flex-row justify-between items-center gap-6 border-b border-slate-700 pb-6 mb-6">
            <div className="flex flex-col">
              <h1 className="text-3xl font-black italic tracking-tighter flex items-center gap-2">
                PIPA <span className="text-blue-400 font-light">VOICE AI</span>
                <Activity className="w-6 h-6 text-blue-400" />
              </h1>
              <span className="text-[10px] font-bold text-blue-300 uppercase tracking-[0.2em] mt-1">
                Sistema de Avaliação de Fluência
              </span>
            </div>

            <div className="flex gap-3">
              <input 
                type="text" 
                placeholder="NOME DA ESCOLA" 
                value={schoolName}
                onChange={(e) => setSchoolName(e.target.value)}
                className="bg-white/10 border border-white/20 px-4 py-2 rounded-lg text-xs outline-none focus:border-blue-400 text-white placeholder-white/40 transition-all w-48"
              />
              <input 
                type="text" 
                placeholder="TURMA" 
                value={className}
                onChange={(e) => setClassName(e.target.value)}
                className="bg-white/10 border border-white/20 px-4 py-2 rounded-lg text-xs outline-none focus:border-blue-400 text-white placeholder-white/40 transition-all w-24 text-center"
              />
            </div>
          </div>

          <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
             <div className="text-center p-3 rounded-lg bg-white/5 backdrop-blur-sm">
                <p className="text-[10px] text-blue-300 uppercase font-bold tracking-wider">IFL Turma</p>
                <p className="text-3xl font-bold mt-1">{avgPpm.toFixed(1)}</p>
             </div>
             <div className="text-center p-3 rounded-lg bg-white/5 backdrop-blur-sm">
                <p className="text-[10px] text-blue-300 uppercase font-bold tracking-wider">Avaliados</p>
                <p className="text-3xl font-bold mt-1">{evaluatedCount}<span className="text-sm text-slate-500">/{totalStudents}</span></p>
             </div>
             <div className="text-center p-3 rounded-lg bg-white/5 backdrop-blur-sm md:col-span-2 flex items-center justify-center">
                 {recordingState === 'recording' ? (
                     <div className="flex items-center gap-2 text-rose-400 animate-pulse">
                         <div className="w-3 h-3 bg-rose-500 rounded-full"></div>
                         <span className="text-xs font-bold uppercase tracking-widest">Gravando Agora...</span>
                     </div>
                 ) : recordingState === 'analyzing' ? (
                    <div className="flex items-center gap-2 text-blue-400 animate-bounce">
                        <Activity className="w-4 h-4" />
                        <span className="text-xs font-bold uppercase tracking-widest">Processando IA...</span>
                    </div>
                 ) : (
                    <span className="text-xs text-slate-500 uppercase tracking-widest">Sistema Pronto</span>
                 )}
             </div>
          </div>
        </div>
      </header>

      <main className="container mx-auto grid grid-cols-1 lg:grid-cols-12 gap-8 px-4 md:px-6">

        {/* Left Column: Student List */}
        <div className="lg:col-span-7 space-y-6">
          <div className="bg-white rounded-xl shadow-sm border border-slate-100 overflow-hidden">
            <div className="p-5 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
              <h2 className="text-xs font-black uppercase text-slate-500 tracking-widest flex items-center gap-2">
                <BookOpen className="w-4 h-4" />
                Lista de Alunos
              </h2>
              <button 
                onClick={addStudent} 
                className="bg-blue-600 hover:bg-blue-700 text-white text-[10px] px-4 py-2 rounded-full font-bold uppercase tracking-wide transition-all flex items-center gap-1 shadow-lg shadow-blue-200"
              >
                <Plus className="w-3 h-3" />
                Adicionar Aluno
              </button>
            </div>

            <div className="overflow-x-auto">
              <table className="w-full text-xs">
                <thead>
                  <tr className="text-slate-400 border-b border-slate-100 uppercase text-[10px] bg-slate-50">
                    <th className="p-4 text-left font-bold tracking-wider">Nome do Aluno</th>
                    <th className="p-4 text-center font-bold tracking-wider w-24">Ação</th>
                    <th className="p-4 text-center font-bold tracking-wider w-20">PPM</th>
                    <th className="p-4 text-center font-bold tracking-wider">Status</th>
                    <th className="p-4 text-center font-bold tracking-wider w-10"></th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {students.map((student) => {
                    const isActive = activeStudentId === student.id;
                    return (
                      <tr 
                        key={student.id} 
                        className={`group transition-all hover:bg-slate-50 ${isActive ? 'bg-rose-50' : ''}`}
                      >
                        <td className="p-4">
                          <input 
                            className={`font-bold uppercase outline-none bg-transparent w-full transition-colors ${isActive ? 'text-rose-700' : 'text-slate-700 focus:text-blue-600'}`}
                            value={student.name} 
                            onChange={(e) => updateStudentName(student.id, e.target.value)}
                          />
                        </td>
                        <td className="p-4 text-center">
                          <button 
                            onClick={() => isActive ? handleStopRecording() : handleStartRecording(student.id)}
                            disabled={activeStudentId !== null && !isActive}
                            className={`
                                p-2 rounded-full transition-all transform hover:scale-110 shadow-sm
                                ${isActive 
                                    ? 'bg-rose-500 text-white shadow-rose-200 animate-pulse' 
                                    : 'bg-white border border-slate-200 text-slate-400 hover:text-blue-600 hover:border-blue-200'
                                }
                                ${activeStudentId !== null && !isActive ? 'opacity-30 cursor-not-allowed' : ''}
                            `}
                          >
                            {isActive ? <Square className="w-4 h-4 fill-current" /> : <Mic className="w-4 h-4" />}
                          </button>
                        </td>
                        <td className="p-4 text-center font-mono font-bold text-slate-600">{student.ppm}</td>
                        <td className="p-4 text-center">
                          <span 
                            className={`
                                px-2 py-1 rounded-md text-[9px] font-black uppercase tracking-wide
                                ${student.ppm === 0 
                                    ? 'bg-slate-100 text-slate-400' 
                                    : student.ppm > 60 
                                        ? 'bg-emerald-100 text-emerald-700' 
                                        : 'bg-amber-100 text-amber-700'
                                }
                            `}
                          >
                            {student.status}
                          </span>
                        </td>
                         <td className="p-4 text-center">
                            <button onClick={() => removeStudent(student.id)} className="text-slate-300 hover:text-rose-500 transition-colors">
                                <Trash2 className="w-3 h-3" />
                            </button>
                         </td>
                      </tr>
                    );
                  })}
                  {students.length === 0 && (
                      <tr>
                          <td colSpan={5} className="p-8 text-center text-slate-400 italic">
                              Nenhum aluno cadastrado.
                          </td>
                      </tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        </div>

        {/* Right Column: Diagnostics & Charts */}
        <div className="lg:col-span-5 space-y-6">

          {/* Live Diagnostic Panel */}
          <div className={`
            rounded-xl border-4 p-6 min-h-[400px] flex flex-col transition-all duration-300 relative overflow-hidden shadow-2xl
            ${activeStudentId !== null ? 'bg-slate-900 border-rose-500' : 'bg-slate-900 border-slate-800'}
          `}>
            {/* Scanline effect */}
            <div className="absolute inset-0 pointer-events-none bg-[linear-gradient(rgba(18,16,16,0)_50%,rgba(0,0,0,0.25)_50%),linear-gradient(90deg,rgba(255,0,0,0.06),rgba(0,255,0,0.02),rgba(0,0,255,0.06))] z-0 bg-[length:100%_2px,3px_100%]"></div>

            <div className="flex justify-between items-center mb-4 border-b border-slate-800 pb-4 relative z-10">
              <h2 className="text-blue-400 font-bold uppercase text-[10px] tracking-widest italic flex items-center gap-2">
                <Activity className="w-3 h-3" />
                Diagnóstico em Tempo Real
              </h2>
              <span className={`
                text-[9px] px-2 py-1 rounded font-bold uppercase tracking-wider
                ${recordingState === 'recording' ? 'bg-rose-600 text-white animate-pulse' : 'bg-slate-800 text-slate-500'}
              `}>
                {recordingState === 'recording' ? 'REC ●' : recordingState === 'analyzing' ? 'ANALISANDO' : 'AGUARDANDO'}
              </span>
            </div>

            <div className="flex-grow font-mono text-xs leading-relaxed whitespace-pre-wrap relative z-10 overflow-y-auto max-h-64 custom-scrollbar">
              {activeStudentId !== null ? (
                <>
                   <span className="text-slate-500 block mb-2">// Transcrição ao vivo...</span>
                   <span className="text-emerald-400">{transcript}</span>
                   {transcript && <span className="animate-pulse inline-block w-2 h-4 bg-emerald-500 ml-1 align-middle"></span>}
                </>
              ) : (
                <div className="h-full flex flex-col justify-center items-center text-slate-600 gap-2">
                    <Mic className="w-8 h-8 opacity-20" />
                    <p className="text-center">Selecione um aluno da lista<br/>para iniciar a gravação e análise.</p>
                </div>
              )}

              {/* Show report if selected student has one and is not currently recording */}
              {activeStudentId === null && students.find(s => s.report)?.report && (
                  <div className="mt-4 pt-4 border-t border-slate-800">
                      <span className="text-slate-500 block mb-2">// Última Análise (Selecionada)</span>
                      {/* Need a way to select a student to view report without recording. 
                          For simplicity, we show report of the last active or logic to select row. 
                          Currently, clicking row starts recording. Let's assume the user just finished.
                      */}
                      {/* To fix this UX, we could add a 'view' mode, but keeping it simple based on the prompt's layout.
                          We will display the report of the student who was just recorded if they exist in state 
                          or maybe add a selection state. For now, let's keep it clean.
                       */}
                  </div>
              )}
            </div>

            {/* Display Report for specific student if available and idle */}
            {activeStudentId === null && (
                 <div className="mt-4 pt-4 border-t border-slate-700 relative z-10">
                     <p className="text-[10px] text-slate-500 uppercase mb-2">Relatórios Recentes:</p>
                     <div className="space-y-2 max-h-32 overflow-y-auto pr-2">
                        {students.filter(s => s.report).map(s => (
                            <div key={s.id} className="bg-slate-800 p-2 rounded border border-slate-700">
                                <span className="text-blue-400 font-bold text-[10px] block mb-1">{s.name} - {s.ppm} PPM</span>
                                <p className="text-slate-300 text-[10px]">{s.report}</p>
                            </div>
                        ))}
                     </div>
                 </div>
            )}

            <div className="mt-auto grid grid-cols-3 gap-2 border-t border-slate-800 pt-4 text-center relative z-10">
              <div className="bg-slate-800/50 rounded p-2">
                <span className="block text-[8px] text-slate-500 uppercase tracking-wider mb-1">Tempo</span>
                <span className="text-white font-bold text-lg font-mono">{activeStudentId ? liveMetrics.time : 0}s</span>
              </div>
              <div className="bg-slate-800/50 rounded p-2">
                <span className="block text-[8px] text-slate-500 uppercase tracking-wider mb-1">Palavras</span>
                <span className="text-white font-bold text-lg font-mono">{activeStudentId ? liveMetrics.words : 0}</span>
              </div>
              <div className="bg-slate-800/50 rounded p-2 border border-slate-700">
                <span className="block text-[8px] text-slate-500 uppercase tracking-wider mb-1">PPM Atual</span>
                <span className={`font-bold text-lg font-mono ${liveMetrics.ppm > 60 ? 'text-emerald-400' : 'text-blue-400'}`}>
                    {activeStudentId ? liveMetrics.ppm : 0}
                </span>
              </div>
            </div>
          </div>

          {/* Chart Section */}
          <div className="bg-white rounded-xl shadow-sm border border-slate-100 p-6">
            <h3 className="text-xs font-black uppercase text-slate-500 tracking-widest mb-6 text-center">Distribuição de Fluência</h3>
            <FluencyChart students={students} />
          </div>

        </div>
      </main>
    </div>
  );
};

export default App;

