            return {
                ...s,
                steps: newSteps,
                ppm: newPpm
            };
        }
        return s;
      }));
    }

    setRecordingState('idle');
    setActiveStudentId(null);
  };

  const handleGenerateDiagnosis = async () => {
      const selectedStudentId = activeStudentId; // Only if active
      // Since we stop recording to click the button, activeStudentId might be null. 
      // We need a way to know WHICH student we are analyzing if none is currently "active" (recording).
