                      </div>
                      <h3 className="text-2xl font-black text-red-600 mb-2 uppercase tracking-tighter">Tempo Encerrado!</h3>
                      <p className="text-slate-600 font-bold mb-6">A coleta foi finalizada automaticamente após 60 segundos.</p>
                      <button 
                          onClick={() => setShowTimeLimitAlert(false)}
                          className="bg-red-600 text-white font-bold py-3 px-8 rounded-full hover:bg-red-700 transition-all shadow-lg shadow-red-200 uppercase tracking-widest text-sm"
                      >
                          Entendido
                      </button>
                  </div>
              </div>
          </div>
      )}

      {/* Header */}
      <header className="bg-slate-900 text-white shadow-xl mb-8 relative overflow-hidden">
        <div className="absolute top-0 right-0 w-64 h-64 bg-blue-500 rounded-full mix-blend-multiply filter blur-3xl opacity-10 animate-blob"></div>
        <div className="absolute top-0 left-0 w-64 h-64 bg-purple-500 rounded-full mix-blend-multiply filter blur-3xl opacity-10 animate-blob animation-delay-2000"></div>

        <div className="container mx-auto p-6 relative z-10">
          <div className="flex flex-col md:flex-row justify-between items-center gap-6 border-b border-slate-700 pb-6 mb-6">
            <div className="flex flex-col">
              <h1 className="text-3xl font-black italic tracking-tighter flex items-center gap-2">
                PIPA <span className="text-blue-400 font-light">VOICE AI</span>
                <Activity className="w-6 h-6 text-blue-400" />
              </h1>
              <span className="text-[10px] font-bold text-blue-300 uppercase tracking-[0.2em] mt-1">
                Sistema de Avaliação de Fluência
              </span>
            </div>

            <div className="flex gap-3 items-center">
              <input 
                type="text" 
                placeholder="NOME DA ESCOLA" 
                value={schoolName}
                onChange={(e) => setSchoolName(e.target.value)}
                className="bg-white/10 border border-white/20 px-4 py-2 rounded-lg text-xs outline-none focus:border-blue-400 text-white placeholder-white/40 transition-all w-48 h-10"
              />

              <div className="relative">
                  <select 
                    value={currentClass}
                    onChange={(e) => {
                        setCurrentClass(e.target.value);
                        setViewStudentId(null); // Clear selection when changing class
                    }}
                    className="bg-blue-600 border border-blue-500 text-white px-4 py-2 rounded-lg text-xs font-bold outline-none focus:ring-2 focus:ring-blue-400 appearance-none h-10 w-24 text-center cursor-pointer hover:bg-blue-700 transition-all"
                  >
                    {CLASSES_LIST.map(cls => (
                        <option key={cls} value={cls}>{cls}</option>
                    ))}
                  </select>
                  <div className="absolute inset-y-0 right-0 flex items-center px-2 pointer-events-none text-white">
                      <svg className="w-3 h-3 fill-current" viewBox="0 0 20 20"><path d="M5.293 7.293a1 1 0 011.414 0L10 10.586l3.293-3.293a1 1 0 111.414 1.414l-4 4a1 1 0 01-1.414 0l-4-4a1 1 0 010-1.414z" clipRule="evenodd" fillRule="evenodd"></path></svg>
                  </div>
              </div>
            </div>
          </div>

          <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
             <div className="text-center p-3 rounded-lg bg-white/5 backdrop-blur-sm">
                <p className="text-[10px] text-blue-300 uppercase font-bold tracking-wider">IFL Turma ({currentClass})</p>
                <p className="text-3xl font-bold mt-1">{avgPpm.toFixed(1)}</p>
             </div>
             <div className="text-center p-3 rounded-lg bg-white/5 backdrop-blur-sm">
                <p className="text-[10px] text-blue-300 uppercase font-bold tracking-wider">Avaliados</p>
                <p className="text-3xl font-bold mt-1">{evaluatedCount}<span className="text-sm text-slate-500">/{totalStudents}</span></p>
             </div>
             <div className="text-center p-3 rounded-lg bg-white/5 backdrop-blur-sm md:col-span-2 flex items-center justify-center">
                 {recordingState === 'recording' ? (
                     <div className="flex items-center gap-2 text-rose-400 animate-pulse">
                         <div className="w-3 h-3 bg-rose-500 rounded-full"></div>
                         <span className="text-xs font-bold uppercase tracking-widest">Gravando Agora...</span>
