              </div>

              <div className="flex gap-2">
                 <button 
                    onClick={exportClassReport} 
                    className="bg-slate-100 hover:bg-slate-200 text-slate-600 text-[10px] px-3 py-2 rounded-full font-bold uppercase tracking-wide transition-all flex items-center gap-1"
