                            className="w-full bg-slate-50 border border-slate-200 rounded-lg px-4 py-3 text-slate-900 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent font-bold transition-all placeholder:font-normal placeholder:text-slate-400"
                        />
