import { Plus, Mic, Square, Activity, Save, Trash2, BookOpen, Layers, Zap, Download, Users, AlertTriangle, PlusCircle, BarChart3 } from 'lucide-react';

const App: React.FC = () => {
  // --- State ---
  const [availableClasses, setAvailableClasses] = useState<string[]>([
    "1º A", "1º B", "2º A", "2º B", "3º A"
  ]);

  const [students, setStudents] = useState<Student[]>([
    { id: 1, name: "AGATHA MAMEDE", ppm: 0, status: "Nível 1", report: "", steps: ["", "", ""], turma: "1º A" },
    { id: 2, name: "MURILLO FELIX", ppm: 0, status: "Nível 1", report: "", steps: ["", "", ""], turma: "1º A" },
    { id: 3, name: "JOÃO SILVA", ppm: 0, status: "Nível 1", report: "", steps: ["", "", ""], turma: "1º B" }
  ]);

  const [currentClass, setCurrentClass] = useState<string>("1º A");
  const [activeStudentId, setActiveStudentId] = useState<number | null>(null);
  const [currentStep, setCurrentStep] = useState<0 | 1 | 2>(0); // 0: Palavras, 1: Pseudo, 2: Texto
  const [recordingState, setRecordingState] = useState<RecordingState>('idle');
  const [transcript, setTranscript] = useState<string>("");
  const [startTime, setStartTime] = useState<number>(0);
  const [liveMetrics, setLiveMetrics] = useState<Metrics>({ words: 0, time: 0, ppm: 0 });
  const [schoolName, setSchoolName] = useState<string>("");
  const [showTimeLimitAlert, setShowTimeLimitAlert] = useState<boolean>(false);

  // View State
  const [currentView, setCurrentView] = useState<'collection' | 'dashboard'>('collection');

  // Modal States
  const [isAddClassModalOpen, setIsAddClassModalOpen] = useState<boolean>(false);
  const [isDeleteClassModalOpen, setIsDeleteClassModalOpen] = useState<boolean>(false);
  const [newClassInput, setNewClassInput] = useState<string>("");

  // We need a selection state to view data without recording
  const [viewStudentId, setViewStudentId] = useState<number | null>(null);

  // --- Refs ---
  const recognitionRef = useRef<any>(null);
  const timerIntervalRef = useRef<number | null>(null);

  // --- Derived State (Filter) ---
  const filteredStudents = students.filter(s => s.turma === currentClass);

  // --- Helpers ---
  const updateLiveMetrics = useCallback(() => {
    if (!startTime) return;
    const now = Date.now();
    const seconds = Math.max(1, Math.floor((now - startTime) / 1000));

    // Simple word count by splitting spaces
    const currentTranscript = transcript.trim();
    const wordCount = currentTranscript ? currentTranscript.split(/\s+/).length : 0;

    const ppm = Math.round((wordCount / seconds) * 60);

    setLiveMetrics({
      words: wordCount,
      time: seconds,
      ppm: ppm
    });
  }, [transcript, startTime]);

  // Update metrics whenever transcript changes during recording
  useEffect(() => {
    if (recordingState === 'recording') {
      updateLiveMetrics();
    }
  }, [transcript, recordingState, updateLiveMetrics]);

  // Timer effect
  useEffect(() => {
    if (recordingState === 'recording') {
      timerIntervalRef.current = window.setInterval(() => {
        updateLiveMetrics();
      }, 1000);
    } else {
      if (timerIntervalRef.current) clearInterval(timerIntervalRef.current);
    }
    return () => {
      if (timerIntervalRef.current) clearInterval(timerIntervalRef.current);
    };
  }, [recordingState, updateLiveMetrics]);

  // Handlers needed for effect below
  const handleStopRecording = useCallback(() => {
    if (recognitionRef.current) {
      recognitionRef.current.stop();
    }

    // Save the transcript to the current step of the active student
    if (activeStudentId !== null) {
      setStudents(prev => prev.map(s => {
        if (s.id === activeStudentId) {
            const newSteps: [string, string, string] = [...s.steps];
            newSteps[currentStep] = transcript;

            // If we are recording the Text step (index 2), we update the PPM
            const newPpm = currentStep === 2 ? liveMetrics.ppm : s.ppm;

            return {
                ...s,
                steps: newSteps,
                ppm: newPpm
            };
        }
        return s;
      }));
    }

    setRecordingState('idle');
    setActiveStudentId(null);
  }, [activeStudentId, currentStep, liveMetrics.ppm, transcript]);

  // Time Limit Check Effect
  useEffect(() => {
    if (recordingState === 'recording' && liveMetrics.time >= 60) {
        handleStopRecording();
        setShowTimeLimitAlert(true);
    }
  }, [liveMetrics.time, recordingState, handleStopRecording]);

  // --- Handlers ---

  const handleStartRecording = (id: number) => {
    if (activeStudentId !== null && activeStudentId !== id) {
      alert("Por favor, finalize a gravação atual antes de iniciar outra.");
      return;
    }

    const w = window as unknown as IWindow;
    const SpeechRecognition = w.SpeechRecognition || w.webkitSpeechRecognition;

    if (!SpeechRecognition) {
      alert("Seu navegador não suporta reconhecimento de fala via Web Speech API.");
      return;
    }

    const recognition = new SpeechRecognition();
    recognition.continuous = true;
    recognition.interimResults = true;
    recognition.lang = 'pt-BR';

    recognition.onresult = (event: any) => {
      let fullTranscript = '';
      for (let i = 0; i < event.results.length; ++i) {
         fullTranscript += event.results[i][0].transcript;
      }
      setTranscript(fullTranscript);
    };

    recognition.onerror = (event: any) => {
      console.error("Speech recognition error", event.error);
    };

    recognition.start();
    recognitionRef.current = recognition;

    setActiveStudentId(id);
    setRecordingState('recording');
    setStartTime(Date.now());
    setTranscript("");
    setLiveMetrics({ words: 0, time: 0, ppm: 0 });
    setShowTimeLimitAlert(false);
  };

  const toggleRecording = (id: number) => {
      if (recordingState === 'recording') {
          if (activeStudentId === id) {
              handleStopRecording();
          }
      } else {
          setViewStudentId(id); // Select for viewing
          handleStartRecording(id);
      }
  };

  const triggerAnalysis = async () => {
      if (!viewStudentId) return alert("Selecione um aluno primeiro.");

      const student = students.find(s => s.id === viewStudentId);
      if (!student) return;

      setRecordingState('analyzing');
      const result = await analyzeReadingFluency(student.steps, student.ppm);

      setStudents(prev => prev.map(s => {
          if (s.id === viewStudentId) {
              return {
                  ...s,
                  status: s.ppm > 60 ? 'Fluente' : 'Iniciante', // Basic logic, AI might refine
                  report: result
              };
          }
          return s;
      }));
      setRecordingState('idle');
  };

  const addStudent = () => {
    const newId = Date.now();
    // Assign new student to the CURRENTLY selected class
    setStudents([...students, { 
        id: newId, 
        name: "NOVO ALUNO", 
        ppm: 0, 
        status: "Nível 1", 
        report: "", 
        steps: ["", "", ""],
        turma: currentClass 
    }]);
  };

  // Add Class Modal Handlers
  const openAddClassModal = () => {
      setNewClassInput("");
      setIsAddClassModalOpen(true);
  };

  const closeAddClassModal = () => {
      setIsAddClassModalOpen(false);
  };

  const confirmAddClass = () => {
      const trimmed = newClassInput.trim();
      if (!trimmed) return;

      if (availableClasses.includes(trimmed)) {
          alert("Esta turma já existe!");
          return;
      }

      // Sort classes with natural numeric order (10 comes after 2)
      const updatedClasses = [...availableClasses, trimmed].sort((a, b) => 
          a.localeCompare(b, 'pt-BR', { numeric: true })
      );

      setAvailableClasses(updatedClasses);
      setCurrentClass(trimmed);
      setViewStudentId(null);
      closeAddClassModal();
  };

  // Delete Class Handlers
  const openDeleteClassModal = () => {
      if (availableClasses.length <= 1) return;
      setIsDeleteClassModalOpen(true);
  };

  const closeDeleteClassModal = () => {
      setIsDeleteClassModalOpen(false);
  };

  const confirmDeleteClass = () => {
      if (availableClasses.length <= 1) return;

      // 1. Remove all students from this class
      const updatedStudents = students.filter(s => s.turma !== currentClass);

      // 2. Remove class from list
      const updatedClasses = availableClasses.filter(c => c !== currentClass);

      // 3. Set new active class (default to first one)
      const nextClass = updatedClasses[0];

      setStudents(updatedStudents);
      setAvailableClasses(updatedClasses);
      setCurrentClass(nextClass);
      setViewStudentId(null);
      setIsDeleteClassModalOpen(false);
  };

  const updateStudentName = (id: number, newName: string) => {
    setStudents(students.map(s => s.id === id ? { ...s, name: newName } : s));
  };

  const removeStudent = (id: number) => {
      if (confirm('Tem certeza que deseja remover este aluno?')) {
          setStudents(students.filter(s => s.id !== id));
          if (viewStudentId === id) setViewStudentId(null);
      }
  };

  const exportClassReport = () => {
      const csvContent = "data:text/csv;charset=utf-8," 
          + "Nome,Turma,PPM,Status,Palavras,Pseudopalavras,Texto,Relatorio\n"
          + filteredStudents.map(s => {
              return `"${s.name}","${s.turma}","${s.ppm}","${s.status}","${s.steps[0].replace(/"/g, '""')}","${s.steps[1].replace(/"/g, '""')}","${s.steps[2].replace(/"/g, '""')}","${s.report.replace(/"/g, '""')}"`;
          }).join("\n");

      const encodedUri = encodeURI(csvContent);
      const link = document.createElement("a");
      link.setAttribute("href", encodedUri);
      link.setAttribute("download", `Relatorio_Fluencia_${currentClass.replace(/\s/g, '')}.csv`);
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
  };

  // Get current student data for display
  const currentStudent = students.find(s => s.id === viewStudentId);
  const displayTranscript = recordingState === 'recording' 
    ? transcript 
    : (currentStudent?.steps[currentStep] || "");

  // --- Stats Calculation (Based on Filtered Students) ---
  const evaluatedCount = filteredStudents.filter(s => s.ppm > 0).length;
  const totalStudents = filteredStudents.length;
  const avgPpm = evaluatedCount > 0 
    ? filteredStudents.reduce((acc, s) => acc + s.ppm, 0) / evaluatedCount 
    : 0;

  // --- Render ---
  return (
    <div className="min-h-screen bg-slate-50 font-sans text-slate-900 pb-12 relative">

      {/* Time Limit Overlay */}
      {showTimeLimitAlert && (
          <div className="fixed inset-0 bg-black/80 z-[100] flex items-center justify-center p-4 backdrop-blur-sm animate-in fade-in zoom-in duration-300">
              <div className="bg-white rounded-2xl p-8 max-w-md w-full text-center shadow-2xl border-4 border-red-500 relative overflow-hidden">
                  {/* Decorative background */}
                  <div className="absolute inset-0 bg-red-50 opacity-20 bg-[radial-gradient(#ef4444_1px,transparent_1px)] [background-size:16px_16px]"></div>

                  <div className="relative z-10">
                      <div className="w-20 h-20 bg-red-100 rounded-full flex items-center justify-center mx-auto mb-6 animate-bounce">
                          <AlertTriangle className="w-10 h-10 text-red-600" />
                      </div>
                      <h3 className="text-2xl font-black text-red-600 mb-2 uppercase tracking-tighter">Tempo Encerrado!</h3>
                      <p className="text-slate-600 font-bold mb-6">A coleta foi finalizada automaticamente após 60 segundos.</p>
                      <button 
                          onClick={() => setShowTimeLimitAlert(false)}
                          className="bg-red-600 text-white font-bold py-3 px-8 rounded-full hover:bg-red-700 transition-all shadow-lg shadow-red-200 uppercase tracking-widest text-sm"
                      >
                          Entendido
                      </button>
                  </div>
              </div>
          </div>
      )}

      {/* Add Class Modal */}
      {isAddClassModalOpen && (
        <div 
            className="fixed inset-0 bg-slate-900/60 z-[100] flex items-center justify-center p-4 backdrop-blur-sm"
            onClick={closeAddClassModal}
        >
            <div 
                className="bg-white rounded-2xl p-8 max-w-md w-full shadow-2xl transform transition-all scale-100 border border-slate-100"
                onClick={(e) => e.stopPropagation()}
            >
                <div className="flex flex-col gap-4">
                    <h3 className="text-xl font-black text-slate-800 uppercase tracking-tight text-center border-b border-slate-100 pb-4">
                        Cadastrar Nova Turma
                    </h3>

                    <div className="py-2">
                        <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-2">
                            Nome da Turma
                        </label>
                        <input 
                            autoFocus
                            type="text" 
                            value={newClassInput}
                            onChange={(e) => setNewClassInput(e.target.value)}
                            onKeyDown={(e) => e.key === 'Enter' && confirmAddClass()}
                            placeholder="Ex: 5º Ano C"
                            className="w-full bg-slate-50 border border-slate-200 rounded-lg px-4 py-3 text-slate-900 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent font-bold transition-all placeholder:font-normal placeholder:text-slate-400"
                        />
                    </div>

                    <div className="flex gap-3 pt-2">
                        <button 
                            onClick={closeAddClassModal}
                            className="flex-1 px-4 py-3 rounded-xl bg-slate-100 text-slate-600 font-bold hover:bg-slate-200 transition-colors uppercase text-xs tracking-wider"
                        >
                            Cancelar
                        </button>
                        <button 
                            onClick={confirmAddClass}
                            disabled={!newClassInput.trim()}
                            className={`
                                flex-1 px-4 py-3 rounded-xl font-bold transition-all uppercase text-xs tracking-wider shadow-lg
                                ${!newClassInput.trim() 
                                    ? 'bg-blue-300 text-white cursor-not-allowed shadow-none' 
                                    : 'bg-blue-600 text-white hover:bg-blue-700 shadow-blue-200 hover:shadow-blue-300 hover:-translate-y-0.5'
                                }
                            `}
                        >
                            Confirmar
                        </button>
                    </div>
                </div>
            </div>
        </div>
      )}

      {/* Delete Class Confirmation Modal */}
      {isDeleteClassModalOpen && (
        <div 
            className="fixed inset-0 bg-slate-900/60 z-[100] flex items-center justify-center p-4 backdrop-blur-sm"
            onClick={closeDeleteClassModal}
        >
            <div 
                className="bg-white rounded-2xl p-8 max-w-md w-full shadow-2xl transform transition-all scale-100 border border-slate-100"
                onClick={(e) => e.stopPropagation()}
            >
                <div className="flex flex-col gap-4 text-center">
                    <div className="w-16 h-16 bg-red-100 rounded-full flex items-center justify-center mx-auto mb-2">
                        <Trash2 className="w-8 h-8 text-red-600" />
                    </div>

                    <h3 className="text-xl font-black text-slate-800 uppercase tracking-tight">
                        Excluir Turma?
                    </h3>

                    <p className="text-slate-600 font-medium">
                        Deseja realmente excluir a turma <span className="font-bold text-slate-900">"{currentClass}"</span>?
                    </p>

                    <p className="text-red-500 text-xs font-bold uppercase tracking-wide bg-red-50 p-3 rounded-lg border border-red-100">
                        Esta ação apagará todos os alunos e diagnósticos vinculados a esta turma e não pode ser desfeita.
                    </p>

                    <div className="flex gap-3 pt-4">
                        <button 
                            onClick={closeDeleteClassModal}
                            className="flex-1 px-4 py-3 rounded-xl bg-slate-100 text-slate-600 font-bold hover:bg-slate-200 transition-colors uppercase text-xs tracking-wider"
                        >
                            Cancelar
                        </button>
                        <button 
                            onClick={confirmDeleteClass}
                            className="flex-1 px-4 py-3 rounded-xl bg-red-600 text-white font-bold hover:bg-red-700 transition-all uppercase text-xs tracking-wider shadow-lg shadow-red-200 hover:shadow-red-300 hover:-translate-y-0.5"
                        >
                            Confirmar Exclusão
                        </button>
                    </div>
                </div>
            </div>
        </div>
      )}

      {/* Header */}
      <header className="bg-slate-900 text-white shadow-xl mb-8 relative overflow-hidden">
        <div className="absolute top-0 right-0 w-64 h-64 bg-blue-500 rounded-full mix-blend-multiply filter blur-3xl opacity-10 animate-blob"></div>
        <div className="absolute top-0 left-0 w-64 h-64 bg-purple-500 rounded-full mix-blend-multiply filter blur-3xl opacity-10 animate-blob animation-delay-2000"></div>

        <div className="container mx-auto p-6 relative z-10">
          <div className="flex flex-col md:flex-row justify-between items-center gap-6 border-b border-slate-700 pb-6 mb-6">
            <div className="flex flex-col">
              <h1 className="text-3xl font-black italic tracking-tighter flex items-center gap-2">
                PIPA <span className="text-blue-400 font-light">VOICE AI</span>
                <Activity className="w-6 h-6 text-blue-400" />
              </h1>
              <span className="text-[10px] font-bold text-blue-300 uppercase tracking-[0.2em] mt-1">
                Sistema de Avaliação de Fluência
              </span>
            </div>

            <div className="flex gap-3 items-center">
              <input 
                type="text" 
                placeholder="NOME DA ESCOLA" 
                value={schoolName}
                onChange={(e) => setSchoolName(e.target.value)}
                className="bg-white/10 border border-white/20 px-4 py-2 rounded-lg text-xs outline-none focus:border-blue-400 text-white placeholder-white/40 transition-all w-48 h-10"
              />

              <div className="flex items-center gap-2 bg-white/5 p-1 rounded-lg border border-white/10">
                  <div className="relative">
                      <select 
                        value={currentClass}
                        onChange={(e) => {
                            setCurrentClass(e.target.value);
                            setViewStudentId(null); // Clear selection when changing class
                        }}
                        className="bg-blue-600 border border-blue-500 text-white px-4 py-2 rounded-lg text-xs font-bold outline-none focus:ring-2 focus:ring-blue-400 appearance-none h-9 min-w-[5rem] text-center cursor-pointer hover:bg-blue-700 transition-all"
                      >
                        {availableClasses.map(cls => (
                            <option key={cls} value={cls}>{cls}</option>
                        ))}
                      </select>
                      <div className="absolute inset-y-0 right-0 flex items-center px-2 pointer-events-none text-white">
                          <svg className="w-3 h-3 fill-current" viewBox="0 0 20 20"><path d="M5.293 7.293a1 1 0 011.414 0L10 10.586l3.293-3.293a1 1 0 111.414 1.414l-4 4a1 1 0 01-1.414 0l-4-4a1 1 0 010-1.414z" clipRule="evenodd" fillRule="evenodd"></path></svg>
                      </div>
                  </div>

                  {/* Delete Class Button */}
                  <button
                    onClick={openDeleteClassModal}
                    disabled={availableClasses.length <= 1}
                    className={`
                        h-9 px-2 rounded-lg flex items-center transition-colors border
                        ${availableClasses.length <= 1 
                            ? 'bg-white/5 text-slate-500 border-transparent cursor-not-allowed opacity-50' 
                            : 'bg-white/10 hover:bg-red-500/20 text-white hover:text-red-400 border-white/10 hover:border-red-500/50'
                        }
                    `}
                    title="Excluir Turma Atual"
                  >
                    <Trash2 className="w-4 h-4" />
                  </button>

                  <button 
                    onClick={openAddClassModal}
                    className="h-9 px-3 bg-white/10 hover:bg-white/20 text-white rounded-lg flex items-center gap-1 transition-colors text-xs font-bold uppercase tracking-wide border border-white/10"
                    title="Adicionar Nova Turma"
                  >
                    <PlusCircle className="w-4 h-4" />
                    <span className="hidden sm:inline">Turma</span>
                  </button>
              </div>

               {/* Dashboard Toggle Button */}
               <button 
                  onClick={() => setCurrentView(currentView === 'collection' ? 'dashboard' : 'collection')}
                  className={`
                    h-10 px-4 rounded-lg flex items-center gap-2 transition-all text-xs font-bold uppercase tracking-wide border shadow-lg
                    ${currentView === 'dashboard' 
                        ? 'bg-emerald-500 text-white border-emerald-400 shadow-emerald-900/20' 
                        : 'bg-white/10 text-white border-white/10 hover:bg-white/20'
                    }
                  `}
                >
                  <BarChart3 className="w-4 h-4" />
                  <span className="hidden sm:inline">{currentView === 'collection' ? 'Dashboard' : 'Coleta'}</span>
                </button>
            </div>
          </div>

          <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
             <div className="text-center p-3 rounded-lg bg-white/5 backdrop-blur-sm">
                <p className="text-[10px] text-blue-300 uppercase font-bold tracking-wider">IFL Turma ({currentClass})</p>
                <p className="text-3xl font-bold mt-1">{avgPpm.toFixed(1)}</p>
             </div>
             <div className="text-center p-3 rounded-lg bg-white/5 backdrop-blur-sm">
                <p className="text-[10px] text-blue-300 uppercase font-bold tracking-wider">Avaliados</p>
                <p className="text-3xl font-bold mt-1">{evaluatedCount}<span className="text-sm text-slate-500">/{totalStudents}</span></p>
             </div>
             <div className="text-center p-3 rounded-lg bg-white/5 backdrop-blur-sm md:col-span-2 flex items-center justify-center">
                 {recordingState === 'recording' ? (
                     <div className="flex items-center gap-2 text-rose-400 animate-pulse">
                         <div className="w-3 h-3 bg-rose-500 rounded-full"></div>
                         <span className="text-xs font-bold uppercase tracking-widest">Gravando Agora...</span>
                     </div>
                 ) : recordingState === 'analyzing' ? (
                    <div className="flex items-center gap-2 text-blue-400 animate-bounce">
                        <Activity className="w-4 h-4" />
                        <span className="text-xs font-bold uppercase tracking-widest">Processando IA...</span>
                    </div>
                 ) : (
                    <span className="text-xs text-slate-500 uppercase tracking-widest">Sistema Pronto: {currentClass}</span>
                 )}
             </div>
          </div>
        </div>
      </header>

      {currentView === 'dashboard' ? (
        <main className="container mx-auto px-4 md:px-6">
            <Dashboard 
                students={filteredStudents} 
                currentClass={currentClass} 
                onBack={() => setCurrentView('collection')} 
            />
        </main>
      ) : (
        <main className="container mx-auto grid grid-cols-1 lg:grid-cols-12 gap-8 px-4 md:px-6">

            {/* Left Column: Student List */}
            <div className="lg:col-span-7 space-y-6">
            <div className="bg-white rounded-xl shadow-sm border border-slate-100 overflow-hidden">
                <div className="p-5 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
                <div className="flex items-center gap-2">
                    <Users className="w-4 h-4 text-slate-500" />
                    <h2 className="text-xs font-black uppercase text-slate-500 tracking-widest">
                    Alunos: <span className="text-blue-600">{currentClass}</span>
                    </h2>
                </div>

                <div className="flex gap-2">
                    <button 
                        onClick={exportClassReport} 
                        className="bg-slate-100 hover:bg-slate-200 text-slate-600 text-[10px] px-3 py-2 rounded-full font-bold uppercase tracking-wide transition-all flex items-center gap-1"
                        title="Exportar Relatório da Turma"
                    >
                        <Download className="w-3 h-3" />
                        CSV
                    </button>
                    <button 
                        onClick={addStudent} 
                        className="bg-blue-600 hover:bg-blue-700 text-white text-[10px] px-4 py-2 rounded-full font-bold uppercase tracking-wide transition-all flex items-center gap-1 shadow-lg shadow-blue-200"
                    >
                        <Plus className="w-3 h-3" />
                        Adicionar
                    </button>
                </div>
                </div>

                <div className="overflow-x-auto">
                <table className="w-full text-xs">
                    <thead>
                    <tr className="text-slate-400 border-b border-slate-100 uppercase text-[10px] bg-slate-50">
                        <th className="p-4 text-left font-bold tracking-wider">Nome do Aluno</th>
                        <th className="p-4 text-center font-bold tracking-wider w-24">Gravar</th>
                        <th className="p-4 text-center font-bold tracking-wider w-20">PPM</th>
                        <th className="p-4 text-center font-bold tracking-wider">Status</th>
                        <th className="p-4 text-center font-bold tracking-wider w-10"></th>
                    </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-100">
                    {filteredStudents.map((student) => {
                        const isRecordingThis = activeStudentId === student.id;
                        const isSelected = viewStudentId === student.id;
                        return (
                        <tr 
                            key={student.id} 
                            onClick={() => setViewStudentId(student.id)}
                            className={`group transition-all hover:bg-slate-50 cursor-pointer ${isSelected ? 'bg-blue-50/50' : ''} ${isRecordingThis ? 'bg-rose-50' : ''}`}
                        >
                            <td className="p-4">
                            <input 
                                className={`font-bold uppercase outline-none bg-transparent w-full transition-colors ${isRecordingThis ? 'text-rose-700' : 'text-slate-700 focus:text-blue-600'}`}
                                value={student.name} 
                                onChange={(e) => updateStudentName(student.id, e.target.value)}
                            />
                            </td>
                            <td className="p-4 text-center">
                            <button 
                                onClick={(e) => { e.stopPropagation(); toggleRecording(student.id); }}
                                disabled={activeStudentId !== null && !isRecordingThis}
                                className={`
                                    p-2 rounded-full transition-all transform hover:scale-110 shadow-sm
                                    ${isRecordingThis 
                                        ? 'bg-rose-500 text-white shadow-rose-200 animate-pulse' 
                                        : 'bg-white border border-slate-200 text-slate-400 hover:text-blue-600 hover:border-blue-200'
                                    }
                                    ${activeStudentId !== null && !isRecordingThis ? 'opacity-30 cursor-not-allowed' : ''}
                                `}
                            >
                                {isRecordingThis ? <Square className="w-4 h-4 fill-current" /> : <Mic className="w-4 h-4" />}
                            </button>
                            </td>
                            <td className="p-4 text-center font-mono font-bold text-slate-600">{student.ppm}</td>
                            <td className="p-4 text-center">
                            <span 
                                className={`
                                    px-2 py-1 rounded-md text-[9px] font-black uppercase tracking-wide
                                    ${student.ppm === 0 
                                        ? 'bg-slate-100 text-slate-400' 
                                        : student.ppm > 60 
                                            ? 'bg-emerald-100 text-emerald-700' 
                                            : 'bg-amber-100 text-amber-700'
                                    }
                                `}
                            >
                                {student.status}
                            </span>
                            </td>
                            <td className="p-4 text-center">
                                <button onClick={(e) => { e.stopPropagation(); removeStudent(student.id); }} className="text-slate-300 hover:text-rose-500 transition-colors">
                                    <Trash2 className="w-3 h-3" />
                                </button>
                            </td>
                        </tr>
                        );
                    })}
                    {filteredStudents.length === 0 && (
                        <tr>
                            <td colSpan={5} className="p-8 text-center text-slate-400 italic">
                                Nenhum aluno nesta turma.
                            </td>
                        </tr>
                    )}
                    </tbody>
                </table>
                </div>
            </div>
            </div>

            {/* Right Column: Diagnostics & Charts */}
            <div className="lg:col-span-5 space-y-6">

            {/* Step Tabs */}
            <div className="flex gap-2 p-1 bg-slate-200 rounded-lg">
                {[
                { id: 0, label: "1. PALAVRAS" },
                { id: 1, label: "2. PSEUDOPALAVRAS" },
                { id: 2, label: "3. TEXTO" }
                ].map(step => (
                <button
                    key={step.id}
                    onClick={() => setCurrentStep(step.id as 0 | 1 | 2)}
                    className={`
                        flex-1 py-2 text-[10px] font-bold uppercase tracking-wider rounded-md transition-all
                        ${currentStep === step.id ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}
                    `}
                >
                    {step.label}
                </button>
                ))}
            </div>

            {/* Live Diagnostic Panel */}
            <div className={`
                rounded-xl border-4 p-6 min-h-[400px] flex flex-col transition-all duration-300 relative overflow-hidden shadow-2xl
                ${recordingState === 'recording' ? 'bg-slate-900 border-rose-500' : 'bg-slate-900 border-slate-800'}
            `}>
                {/* Scanline effect */}
                <div className="absolute inset-0 pointer-events-none bg-[linear-gradient(rgba(18,16,16,0)_50%,rgba(0,0,0,0.25)_50%),linear-gradient(90deg,rgba(255,0,0,0.06),rgba(0,255,0,0.02),rgba(0,0,255,0.06))] z-0 bg-[length:100%_2px,3px_100%]"></div>

                <div className="flex justify-between items-center mb-4 border-b border-slate-800 pb-4 relative z-10">
                <h2 className="text-blue-400 font-bold uppercase text-[10px] tracking-widest italic flex items-center gap-2">
                    <Layers className="w-3 h-3" />
                    {currentStep === 0 ? "Leitura de Palavras" : currentStep === 1 ? "Leitura de Pseudopalavras" : "Leitura de Texto"}
                </h2>
                <span className={`
                    text-[9px] px-2 py-1 rounded font-bold uppercase tracking-wider
                    ${recordingState === 'recording' ? 'bg-rose-600 text-white animate-pulse' : 'bg-slate-800 text-slate-500'}
                `}>
                    {recordingState === 'recording' ? 'GRAVANDO' : recordingState === 'analyzing' ? 'PROCESSANDO' : 'VISUALIZANDO'}
                </span>
                </div>

                <div className="flex-grow font-mono text-xs leading-relaxed whitespace-pre-wrap relative z-10 overflow-y-auto max-h-64 custom-scrollbar">
                {viewStudentId ? (
                    <>
                    <span className="text-slate-500 block mb-2">
                        {recordingState === 'recording' ? `// Gravando etapa ${currentStep + 1}...` : `// Conteúdo gravado (Etapa ${currentStep + 1}):`}
                    </span>
                    <span className={recordingState === 'recording' ? "text-rose-400" : "text-emerald-400"}>
                        {displayTranscript || <span className="text-slate-600 italic">Nenhum áudio gravado para esta etapa.</span>}
                    </span>
                    {recordingState === 'recording' && <span className="animate-pulse inline-block w-2 h-4 bg-rose-500 ml-1 align-middle"></span>}
                    </>
                ) : (
                    <div className="h-full flex flex-col justify-center items-center text-slate-600 gap-2">
                        <Mic className="w-8 h-8 opacity-20" />
                        <p className="text-center">Selecione um aluno da lista<br/>para visualizar ou gravar.</p>
                    </div>
                )}
                </div>

                {/* Metrics Footer (Only visible if recording or step 3) */}
                <div className="mt-auto grid grid-cols-3 gap-2 border-t border-slate-800 pt-4 text-center relative z-10">
                <div className="bg-slate-800/50 rounded p-2">
                    <span className="block text-[8px] text-slate-500 uppercase tracking-wider mb-1">Tempo</span>
                    <span className={`font-bold text-lg font-mono ${recordingState === 'recording' && liveMetrics.time >= 55 ? 'text-red-500 animate-pulse' : 'text-white'}`}>
                        {recordingState === 'recording' ? liveMetrics.time : 0}s
                    </span>
                </div>
                <div className="bg-slate-800/50 rounded p-2">
                    <span className="block text-[8px] text-slate-500 uppercase tracking-wider mb-1">Palavras</span>
                    <span className="text-white font-bold text-lg font-mono">{recordingState === 'recording' ? liveMetrics.words : 0}</span>
                </div>
                <div className="bg-slate-800/50 rounded p-2 border border-slate-700">
                    <span className="block text-[8px] text-slate-500 uppercase tracking-wider mb-1">PPM Atual</span>
                    <span className={`font-bold text-lg font-mono ${liveMetrics.ppm > 60 ? 'text-emerald-400' : 'text-blue-400'}`}>
                        {recordingState === 'recording' ? liveMetrics.ppm : (currentStudent?.ppm || 0)}
                    </span>
                </div>
                </div>
            </div>

            {/* Action Button: Generate Diagnosis */}
            <button 
                onClick={triggerAnalysis}
                disabled={!viewStudentId || recordingState !== 'idle'}
                className={`
                    w-full py-4 rounded-xl font-black uppercase tracking-widest text-sm flex items-center justify-center gap-2 shadow-lg transition-all
                    ${!viewStudentId || recordingState !== 'idle' 
                        ? 'bg-slate-200 text-slate-400 cursor-not-allowed' 
                        : 'bg-emerald-500 text-white hover:bg-emerald-600 shadow-emerald-200 hover:scale-[1.02]'
                    }
                `}
            >
                <Zap className="w-5 h-5 fill-current" />
                Gerar Diagnóstico CAED
            </button>

            {/* Last Report View */}
            {currentStudent?.report && (
                <div className="bg-white rounded-xl shadow-sm border border-slate-100 p-6">
                    <h3 className="text-xs font-black uppercase text-slate-500 tracking-widest mb-4">Relatório Técnico</h3>
                    <div className="bg-slate-50 p-4 rounded-lg text-xs leading-relaxed text-slate-700 whitespace-pre-wrap border border-slate-200">
                        {currentStudent.report}
                    </div>
                </div>
            )}

            {/* Chart Section */}
            <div className="bg-white rounded-xl shadow-sm border border-slate-100 p-6">
                <h3 className="text-xs font-black uppercase text-slate-500 tracking-widest mb-6 text-center">Distribuição de Fluência ({currentClass})</h3>
                <FluencyChart students={filteredStudents} />
            </div>

            </div>
        </main>
      )}
    </div>
  );
};

export default App;

export type FluencyLevel = 'Nível 1' | 'Nível 2' | 'Nível 3' | 'Nível 4' | 'Iniciante' | 'Fluente';

export interface Student {
  id: number;
  name: string;
  ppm: number;
  status: FluencyLevel;
  report: string;
  steps: [string, string, string]; // [Palavras, Pseudopalavras, Texto]
  turma: string;
}

export interface Metrics {
  words: number;
  time: number;
  ppm: number;
}

// Minimal type definitions for Web Speech API since it's not fully standard in all TS configs
export interface IWindow extends Window {
  webkitSpeechRecognition: any;
  SpeechRecognition: any;
}

export type RecordingState = 'idle' | 'recording' | 'analyzing';

import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const analyzeReadingFluency = async (
  steps: [string, string, string], 
  ppm: number
): Promise<string> => {
  try {
    const prompt = `
      Atue como um especialista em avaliação de fluência leitora (padrão CAED/alfabetização).

      Analise o seguinte circuito de leitura de um aluno:

      1. LEITURA DE PALAVRAS ISOLADAS:
      "${steps[0]}"

      2. LEITURA DE PSEUDOPALAVRAS (Decodificação):
      "${steps[1]}"

      3. LEITURA DE TEXTO CONECTADO:
      "${steps[2]}"

      DADOS QUANTITATIVOS (Do Texto):
      - Velocidade: ${ppm} PPM

      Gere um diagnóstico estruturado.

      IMPORTANTE: A Classificação deve ser EXATAMENTE uma das seguintes (baseada em PPM e Rota Fonológica):
      - "Nível 1": Não lê palavras (PPM 0-10, falha na decodificação).
      - "Nível 2": Lê algumas palavras isoladas com muitos erros (PPM 10-30).
      - "Nível 3": Lê palavras simples, trava em complexas (PPM 30-50).
      - "Nível 4": Lê frases curtas silabando (PPM 50-70).
      - "Iniciante": Lê textos curtos, baixa fluência (PPM 70-90).
      - "Fluente": Leitura rítmica, precisa e respeita pontuação (PPM > 90).

      Retorne no formato:
      1. **Precisão de Decodificação**: Análise breve.
      2. **Fluência e Ritmo**: Análise breve.
      3. **Classificação**: [Nível 1 | Nível 2 | Nível 3 | Nível 4 | Iniciante | Fluente]
      4. **Recomendação Pedagógica**: Uma ação prática.

      Se algum campo estiver vazio, use os dados disponíveis para estimar.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });

    return response.text || "Não foi possível gerar a análise.";
  } catch (error) {
    console.error("Error analyzing fluency:", error);
    return "Erro ao conectar com a IA. Verifique sua conexão ou tente novamente.";
  }
};

import React, { useMemo, useState } from 'react';
import { Student, FluencyLevel } from '../types';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip as RechartsTooltip, 
  ResponsiveContainer, PieChart, Pie, Cell, Legend 
} from 'recharts';
import { ArrowLeft, Users, Zap, Target, Award, TrendingUp, Info, X, Download } from 'lucide-react';

interface DashboardProps {
  students: Student[];
  currentClass: string;
  onBack: () => void;
}

// Color Palette Definition
const COLORS: Record<FluencyLevel, string> = {
  'Nível 1': '#ef4444', // Red-500
  'Nível 2': '#dc2626', // Red-600
  'Nível 3': '#f97316', // Orange-500
  'Nível 4': '#f59e0b', // Amber-500
  'Iniciante': '#3b82f6', // Blue-500
  'Fluente': '#10b981', // Emerald-500
};

const LEGEND_DATA = [
  { level: 'Nível 1', desc: 'Pré-leitor: Não decodifica palavras isoladas. Dificuldade severa.', color: 'bg-red-500' },
  { level: 'Nível 2', desc: 'Leitor de Palavras: Lê palavras isoladas com muitos erros. Silabação excessiva.', color: 'bg-red-600' },
  { level: 'Nível 3', desc: 'Em Construção: Lê palavras simples corretamente, trava em complexas.', color: 'bg-orange-500' },
  { level: 'Nível 4', desc: 'Fraseado: Lê frases curtas, ainda com silabação, mas compreende o sentido básico.', color: 'bg-amber-500' },
  { level: 'Iniciante', desc: 'Transição: Lê textos curtos com baixa fluência. Início da automação.', color: 'bg-blue-500' },
  { level: 'Fluente', desc: 'Consolidado: Leitura rítmica, precisa, respeita pontuação e entonação.', color: 'bg-emerald-500' },
];

const Dashboard: React.FC<DashboardProps> = ({ students, currentClass, onBack }) => {
  const [isLegendOpen, setIsLegendOpen] = useState(false);

  // --- Data Processing & Statistics ---
  const stats = useMemo(() => {
    const evaluated = students.filter(s => s.ppm > 0);
    const totalEvaluated = evaluated.length;

    if (totalEvaluated === 0) return null;

    const totalPpm = evaluated.reduce((acc, s) => acc + s.ppm, 0);
    const avgPpm = Math.round(totalPpm / totalEvaluated);

    // Heuristic for Accuracy
    const calculateAccuracy = (ppm: number) => Math.min(100, Math.max(60, 70 + (ppm * 0.3)));
    const avgAccuracy = Math.round(
      evaluated.reduce((acc, s) => acc + calculateAccuracy(s.ppm), 0) / totalEvaluated
    );

    // Classification Counts (Initialize all to 0)
    const levels: Record<FluencyLevel, number> = {
      'Nível 1': 0, 'Nível 2': 0, 'Nível 3': 0, 'Nível 4': 0, 'Iniciante': 0, 'Fluente': 0
    };

    evaluated.forEach(s => {
      if (levels[s.status] !== undefined) {
        levels[s.status]++;
      } else {
        // Fallback if status doesn't match keys (should handle legacy data)
        levels['Nível 1']++;
      }
    });

    // Determine Class Level
    let classLevel = "EM DESENVOLVIMENTO";
    if (levels['Fluente'] > totalEvaluated * 0.5) classLevel = "TURMA FLUENTE";
    else if ((levels['Nível 1'] + levels['Nível 2']) > totalEvaluated * 0.4) classLevel = "ATENÇÃO PRIORITÁRIA";

    // Mode (Most frequent level)
    const mode = (Object.keys(levels) as FluencyLevel[]).reduce((a, b) => levels[a] > levels[b] ? a : b);

    return {
      totalEvaluated,
      avgPpm,
      avgAccuracy,
      levels,
      classLevel,
      evaluated,
      mode
    };
  }, [students]);

  // --- Chart Data Helpers ---
  const pieData = stats ? Object.entries(stats.levels).map(([name, value]) => ({
    name,
    value,
    color: COLORS[name as FluencyLevel]
  })).filter(d => d.value > 0) : [];

  const barData = stats ? [
    { name: 'Palavras', score: Math.min(100, stats.avgAccuracy + 5) },
    { name: 'Pseudopalavras', score: Math.min(100, stats.avgAccuracy - 10) },
    { name: 'Texto (PPM)', score: stats.avgPpm }, 
  ] : [];

  // --- CSV Export Handler ---
  const handleExport = () => {
    if (!stats) return;

    const headers = ["Nome do Aluno", "Turma", "PPM", "Nível Fluência", "Pseudopalavras (Transcrição)", "Erros Estimados (Pseudo)"];

    const rows = stats.evaluated.map(s => {
      // Heuristic for errors in pseudo based on level since we don't have exact count stored
      let errorsEst = "Baixo";
      if (s.status === 'Nível 1' || s.status === 'Nível 2') errorsEst = "Crítico";
      else if (s.status === 'Nível 3' || s.status === 'Nível 4') errorsEst = "Moderado";

      return [
        `"${s.name}"`,
        `"${s.turma}"`,
        s.ppm,
        `"${s.status}"`,
        `"${s.steps[1].replace(/"/g, '""')}"`, // Transcrição Pseudo
        `"${errorsEst}"`
      ].join(",");
    });

    const csvContent = "data:text/csv;charset=utf-8," + [headers.join(","), ...rows].join("\n");
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `Dados_Turma_${currentClass.replace(/\s/g, '')}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // --- Empty State ---
  if (!stats) {
    return (
      <div className="flex flex-col items-center justify-center h-[60vh] text-slate-400">
        <Users className="w-16 h-16 mb-4 opacity-20" />
        <h2 className="text-xl font-bold uppercase tracking-widest">Sem dados para análise</h2>
        <p className="text-sm mt-2">Realize coletas na turma {currentClass} para gerar o dashboard.</p>
        <button onClick={onBack} className="mt-6 px-6 py-2 bg-blue-600 text-white rounded-lg font-bold hover:bg-blue-700 transition-all">
          Voltar para Coleta
        </button>
      </div>
    );
  }

  return (
    <div className="animate-in fade-in slide-in-from-bottom-4 duration-500 relative">

      {/* Legend Modal */}
      {isLegendOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 backdrop-blur-sm p-4" onClick={() => setIsLegendOpen(false)}>
           <div className="bg-white rounded-2xl shadow-2xl max-w-lg w-full overflow-hidden border border-slate-100" onClick={e => e.stopPropagation()}>
              <div className="bg-slate-50 p-4 border-b border-slate-100 flex justify-between items-center">
                 <h3 className="font-black text-slate-700 uppercase tracking-widest text-sm flex items-center gap-2">
                    <Info className="w-4 h-4 text-blue-500" /> Matriz de Fluência
                 </h3>
                 <button onClick={() => setIsLegendOpen(false)} className="text-slate-400 hover:text-slate-600"><X className="w-5 h-5" /></button>
              </div>
              <div className="p-6 space-y-4">
                 {LEGEND_DATA.map((item) => (
                    <div key={item.level} className="flex gap-4 items-start">
                       <div className={`w-3 h-3 rounded-full mt-1.5 shrink-0 ${item.color}`}></div>
                       <div>
                          <p className="font-bold text-xs uppercase text-slate-800">{item.level}</p>
                          <p className="text-xs text-slate-500 leading-relaxed">{item.desc}</p>
                       </div>
                    </div>
                 ))}
              </div>
              <div className="bg-slate-50 p-4 text-center">
                 <button onClick={() => setIsLegendOpen(false)} className="text-xs font-bold text-blue-600 uppercase tracking-wider hover:underline">Fechar Legenda</button>
              </div>
           </div>
        </div>
      )}

      {/* Header / Nav */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-8">
        <div>
           <button 
             onClick={onBack}
             className="flex items-center gap-2 text-slate-500 hover:text-blue-600 transition-colors font-bold uppercase text-xs tracking-wider mb-2"
           >
             <ArrowLeft className="w-4 h-4" /> Voltar à Coleta
           </button>
           <div className="flex items-center gap-3">
             <h1 className="text-2xl font-black text-slate-800 uppercase tracking-tight">
               Dashboard <span className="text-blue-600">:: {currentClass}</span>
             </h1>
             <button 
               onClick={() => setIsLegendOpen(true)}
               className="p-1.5 rounded-full bg-slate-100 text-slate-500 hover:bg-blue-100 hover:text-blue-600 transition-colors"
               title="Ver Legenda Técnica"
             >
               <Info className="w-4 h-4" />
             </button>
           </div>
        </div>

        <div className="flex items-center gap-4">
           <button 
             onClick={handleExport}
             className="flex items-center gap-2 bg-slate-800 text-white px-4 py-2 rounded-lg text-xs font-bold uppercase tracking-wide hover:bg-slate-700 transition-all shadow-lg shadow-slate-200"
           >
             <Download className="w-4 h-4" /> Baixar Dados (CSV)
           </button>
           <div className="text-right hidden md:block">
              <span className="block text-[10px] font-bold text-slate-400 uppercase tracking-widest">Diagnóstico Geral</span>
              <span className={`text-lg font-black uppercase ${
                  stats.classLevel === 'TURMA FLUENTE' ? 'text-emerald-500' : 
                  stats.classLevel === 'ATENÇÃO PRIORITÁRIA' ? 'text-rose-500' : 'text-amber-500'
              }`}>
                {stats.classLevel}
              </span>
           </div>
        </div>
      </div>

      {/* KPI Cards */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-8">
        <div className="bg-white p-5 rounded-xl shadow-sm border border-slate-100 flex flex-col justify-between relative overflow-hidden group">
            <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:scale-110 transition-transform"><Zap className="w-12 h-12 text-blue-600" /></div>
            <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Média PPM</span>
            <span className="text-3xl font-black text-slate-800 mt-2">{stats.avgPpm}</span>
            <div className="w-full bg-slate-100 h-1 mt-4 rounded-full overflow-hidden">
                <div className="bg-blue-500 h-full" style={{ width: `${Math.min(100, stats.avgPpm)}%` }}></div>
            </div>
        </div>

        <div className="bg-white p-5 rounded-xl shadow-sm border border-slate-100 flex flex-col justify-between relative overflow-hidden group">
            <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:scale-110 transition-transform"><Target className="w-12 h-12 text-emerald-600" /></div>
            <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Precisão Est.</span>
            <span className="text-3xl font-black text-slate-800 mt-2">{stats.avgAccuracy}%</span>
            <div className="w-full bg-slate-100 h-1 mt-4 rounded-full overflow-hidden">
                <div className="bg-emerald-500 h-full" style={{ width: `${stats.avgAccuracy}%` }}></div>
            </div>
        </div>

        <div className="bg-white p-5 rounded-xl shadow-sm border border-slate-100 flex flex-col justify-between relative overflow-hidden group">
            <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:scale-110 transition-transform"><Users className="w-12 h-12 text-violet-600" /></div>
            <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Alunos Avaliados</span>
            <span className="text-3xl font-black text-slate-800 mt-2">{stats.totalEvaluated}</span>
            <span className="text-[10px] text-slate-400 font-bold mt-4 block">De {students.length} matriculados</span>
        </div>

        <div className="bg-white p-5 rounded-xl shadow-sm border border-slate-100 flex flex-col justify-between relative overflow-hidden group">
            <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:scale-110 transition-transform"><Award className="w-12 h-12 text-amber-500" /></div>
            <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Moda (Nível)</span>
            <span className="text-xl font-black text-slate-800 mt-2 leading-tight truncate" style={{ color: COLORS[stats.mode] }}>
                {stats.mode}
            </span>
            <div className="flex gap-1 mt-4">
                 {/* Visual indicator of distribution */}
                 {Object.entries(stats.levels).map(([lvl, count]) => (
