import React from 'react';
import { PieChart, Pie, Cell, Tooltip, ResponsiveContainer, Legend } from 'recharts';
import { Student, FluencyLevel } from '../types';

interface FluencyChartProps {
  students: Student[];
}

const COLORS: Record<string, string> = {
  'Nível 1': '#ef4444',
  'Nível 2': '#dc2626',
  'Nível 3': '#f97316',
  'Nível 4': '#f59e0b',
  'Iniciante': '#3b82f6',
  'Fluente': '#10b981',
};

const FluencyChart: React.FC<FluencyChartProps> = ({ students }) => {
  const evaluatedStudents = students.filter(s => s.ppm > 0);

  if (evaluatedStudents.length === 0) {
     return (
        <div className="h-48 w-full flex items-center justify-center text-slate-400 text-xs uppercase tracking-widest">
           Nenhum aluno avaliado
        </div>
     );
  }

  // Count occurrences of each level
  const counts: Record<string, number> = {};
  evaluatedStudents.forEach(s => {
    counts[s.status] = (counts[s.status] || 0) + 1;
  });

  const data = Object.entries(counts).map(([name, value]) => ({
    name,
    value
  }));

  return (
    <div className="h-64 w-full">
      <ResponsiveContainer width="100%" height="100%">
        <PieChart>
          <Pie
            data={data}
            cx="50%"
            cy="50%"
            innerRadius={60}
            outerRadius={80}
            paddingAngle={5}
            dataKey="value"
          >
            {data.map((entry, index) => (
              <Cell key={`cell-${index}`} fill={COLORS[entry.name] || '#ccc'} />
            ))}
          </Pie>
          <Tooltip 
            contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px rgba(0,0,0,0.1)' }}
            itemStyle={{ fontSize: '12px', fontWeight: 'bold' }}
          />
          <Legend 
            verticalAlign="bottom" 
            height={36} 
            iconType="circle"
            wrapperStyle={{ fontSize: '10px', fontWeight: 'bold', textTransform: 'uppercase' }}
          />
        </PieChart>
      </ResponsiveContainer>
    </div>
  );
};

