import { GoogleGenAI } from "@google/genai";
import { Student } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const analyzeReadingFluency = async (
  steps: [string, string, string], 
  ppm: number
): Promise<string> => {
  try {
    const prompt = `
      Atue como um especialista em avaliação de fluência leitora (padrão CAED/alfabetização).

      Analise o seguinte circuito de leitura de um aluno:

      1. LEITURA DE PALAVRAS ISOLADAS:
      "${steps[0]}"

      2. LEITURA DE PSEUDOPALAVRAS (Decodificação):
      "${steps[1]}"

      3. LEITURA DE TEXTO CONECTADO:
      "${steps[2]}"

      DADOS QUANTITATIVOS (Do Texto):
      - Velocidade: ${ppm} PPM

      Gere um diagnóstico estruturado.

      IMPORTANTE: A Classificação deve ser EXATAMENTE uma das seguintes (baseada em PPM e Rota Fonológica):
      - "Nível 1": Não lê palavras (PPM 0-10, falha na decodificação).
      - "Nível 2": Lê algumas palavras isoladas com muitos erros (PPM 10-30).
      - "Nível 3": Lê palavras simples, trava em complexas (PPM 30-50).
      - "Nível 4": Lê frases curtas silabando (PPM 50-70).
      - "Iniciante": Lê textos curtos, baixa fluência (PPM 70-90).
      - "Fluente": Leitura rítmica, precisa e respeita pontuação (PPM > 90).

      Retorne no formato:
      1. **Precisão de Decodificação**: Análise breve.
      2. **Fluência e Ritmo**: Análise breve.
      3. **Classificação**: [Nível 1 | Nível 2 | Nível 3 | Nível 4 | Iniciante | Fluente]
      4. **Recomendação Pedagógica**: Uma ação prática.

      Se algum campo estiver vazio, use os dados disponíveis para estimar.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });

    return response.text || "Não foi possível gerar a análise.";
  } catch (error) {
    console.error("Error analyzing fluency:", error);
    return "Erro ao conectar com a IA. Verifique sua conexão ou tente novamente.";
  }
};

export const generateClassAnalysis = async (
  className: string,
  students: Student[]
): Promise<string> => {
  try {
    const evaluated = students.filter(s => s.ppm > 0);

    if (evaluated.length === 0) return "Não há dados suficientes para gerar um parecer da turma.";

    // Summarize data to send to AI to save tokens/complexity
    const summary = evaluated.map(s => `- Aluno: ${s.name}, Nível: ${s.status}, PPM: ${s.ppm}`).join("\n");
    const counts = evaluated.reduce((acc, s) => {
      acc[s.status] = (acc[s.status] || 0) + 1;
      return acc;
    }, {} as Record<string, number>);

    const prompt = `
      Atue como um coordenador pedagógico sênior.
      Analise os dados consolidados da turma "${className}":

      Total Avaliados: ${evaluated.length}
      Distribuição: ${JSON.stringify(counts)}

      Lista Detalhada:
      ${summary}

      Gere um PARECER TÉCNICO DA TURMA (Máx 200 palavras) contendo:
      1. **Visão Geral**: Qual o perfil predominante da sala?
      2. **Pontos de Atenção**: Quais alunos ou grupos precisam de intervenção imediata?
      3. **Estratégia Coletiva**: Sugira 2 atividades para a turma toda baseadas no nível médio.

      Use tom profissional e acolhedor.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });

    return response.text || "Não foi possível gerar o parecer da turma.";

  } catch (error) {
    console.error("Error generating class analysis:", error);
    return "Erro ao conectar com a IA para análise de turma.";
  }
};

