                  <button onClick={openDeleteClassModal} disabled={availableClasses.length <= 1} className={`h-9 px-2 rounded-lg flex items-center transition-colors border ${availableClasses.length <= 1 ? 'bg-white/5 text-slate-500 border-transparent cursor-not-allowed opacity-50' : 'bg-white/10 hover:bg-red-500/20 text-white hover:text-red-400 border-white/10 hover:border-red-500/50'}`}><Trash2 className="w-4 h-4" /></button>
                  <button onClick={openAddClassModal} className="h-9 px-3 bg-white/10 hover:bg-white/20 text-white rounded-lg flex items-center gap-1 transition-colors text-xs font-bold uppercase tracking-wide border border-white/10"><PlusCircle className="w-4 h-4" /><span className="hidden sm:inline">Turma</span></button>
              </div>
               <button onClick={() => setCurrentView(currentView === 'collection' ? 'dashboard' : 'collection')} className={`h-10 px-4 rounded-lg flex items-center gap-2 transition-all text-xs font-bold uppercase tracking-wide border shadow-lg ${currentView === 'dashboard' ? 'bg-emerald-500 text-white border-emerald-400 shadow-emerald-900/20' : 'bg-white/10 text-white border-white/10 hover:bg-white/20'}`}><BarChart3 className="w-4 h-4" /><span className="hidden sm:inline">{currentView === 'collection' ? 'Dashboard' : 'Coleta'}</span></button>
            </div>
          </div>

          <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
             <div className="text-center p-3 rounded-lg bg-white/5 backdrop-blur-sm">
                <p className="text-[10px] text-blue-300 uppercase font-bold tracking-wider">IFL Turma ({currentClass})</p>
                <p className="text-3xl font-bold mt-1">{avgPpm.toFixed(1)}</p>
             </div>
             <div className="text-center p-3 rounded-lg bg-white/5 backdrop-blur-sm">
                <p className="text-[10px] text-blue-300 uppercase font-bold tracking-wider">Avaliados</p>
                <p className="text-3xl font-bold mt-1">{evaluatedCount}<span className="text-sm text-slate-500">/{totalStudents}</span></p>
             </div>
             <div className="text-center p-3 rounded-lg bg-white/5 backdrop-blur-sm md:col-span-2 flex items-center justify-center gap-4">
                 {recordingState === 'recording' ? (
                     <div className="flex items-center gap-2 text-rose-400 animate-pulse">
                         <div className="w-3 h-3 bg-rose-500 rounded-full"></div>
                         <span className="text-xs font-bold uppercase tracking-widest">Gravando Agora...</span>
                     </div>
                 ) : recordingState === 'analyzing' ? (
                    <div className="flex items-center gap-2 text-blue-400 animate-bounce">
                        <Activity className="w-4 h-4" />
                        <span className="text-xs font-bold uppercase tracking-widest">Processando IA...</span>
                    </div>
                 ) : (
                    <>
                        <button onClick={handleGenerateClassReport} className="flex items-center gap-1.5 bg-white/10 hover:bg-white/20 px-3 py-1.5 rounded-lg text-[10px] font-bold uppercase tracking-wide transition-all border border-white/10">
                            <FileText className="w-3 h-3 text-blue-300" /> Ver Parecer da Turma
                        </button>
                        <button onClick={handlePrintClassResults} className="flex items-center gap-1.5 bg-white/10 hover:bg-white/20 px-3 py-1.5 rounded-lg text-[10px] font-bold uppercase tracking-wide transition-all border border-white/10">
                            <Printer className="w-3 h-3 text-emerald-300" /> Baixar PDF
                        </button>
                    </>
                 )}
             </div>
          </div>
        </div>
      </header>

      {currentView === 'dashboard' ? (
        <main className="container mx-auto px-4 md:px-6">
            <Dashboard 
                students={filteredStudents} 
                allStudents={students}
                currentClass={currentClass} 
                onBack={() => setCurrentView('collection')} 
            />
        </main>
      ) : (
        <main className="container mx-auto grid grid-cols-1 lg:grid-cols-12 gap-8 px-4 md:px-6">

            {/* Left Column: Student List */}
            <div className="lg:col-span-7 space-y-6">
            <div className="bg-white rounded-xl shadow-sm border border-slate-100 overflow-hidden">
                <div className="p-5 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
                <div className="flex items-center gap-2">
                    <Users className="w-4 h-4 text-slate-500" />
                    <h2 className="text-xs font-black uppercase text-slate-500 tracking-widest">
                    Alunos: <span className="text-blue-600">{currentClass}</span>
                    </h2>
                </div>

                <div className="flex gap-2">
                    <button onClick={exportClassReport} className="bg-slate-100 hover:bg-slate-200 text-slate-600 text-[10px] px-3 py-2 rounded-full font-bold uppercase tracking-wide transition-all flex items-center gap-1" title="Exportar Relatório da Turma"><Download className="w-3 h-3" /> CSV</button>
                    <button onClick={addStudent} className="bg-blue-600 hover:bg-blue-700 text-white text-[10px] px-4 py-2 rounded-full font-bold uppercase tracking-wide transition-all flex items-center gap-1 shadow-lg shadow-blue-200"><Plus className="w-3 h-3" /> Adicionar</button>
                </div>
                </div>

                <div className="overflow-x-auto">
                <table className="w-full text-xs">
                    <thead>
                    <tr className="text-slate-400 border-b border-slate-100 uppercase text-[10px] bg-slate-50">
                        <th className="p-4 text-left font-bold tracking-wider">Nome do Aluno</th>
                        <th className="p-4 text-center font-bold tracking-wider w-16">Gravar</th>
                        <th className="p-4 text-center font-bold tracking-wider w-16">PPM</th>
                        <th className="p-4 text-center font-bold tracking-wider">Status</th>
                        <th className="p-4 text-center font-bold tracking-wider w-12">Laudo</th>
                        <th className="p-4 text-center font-bold tracking-wider w-10"></th>
                    </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-100">
