                h2 { margin-top: 0; color: #64748b; font-size: 16px; margin-bottom: 30px; }
                table { width: 100%; border-collapse: collapse; margin-top: 20px; }
                th, td { border: 1px solid #e2e8f0; padding: 10px; text-align: left; font-size: 12px; }
                th { background-color: #f1f5f9; text-transform: uppercase; font-weight: bold; }
                .status-badge { padding: 4px 8px; border-radius: 4px; font-weight: bold; display: inline-block; font-size: 10px; text-transform: uppercase; border: 1px solid #ccc; }
                .footer { margin-top: 40px; font-size: 10px; color: #94a3b8; border-top: 1px solid #e2e8f0; padding-top: 10px; }
            </style>
        </head>
        <body>
            <h1>Relatório de Fluência Leitora</h1>
            <h2>Turma: ${currentClass} | Escola: ${schoolName || 'Não informada'} | Data: ${date}</h2>

            <table>
                <thead>
                    <tr>
                        <th>Aluno</th>
                        <th style="text-align: center;">PPM</th>
                        <th style="text-align: center;">Nível</th>
                    </tr>
                </thead>
                <tbody>
                    ${filteredStudents.map(s => `
                        <tr>
                            <td>${s.name}</td>
                            <td style="text-align: center;">${s.ppm}</td>
                            <td style="text-align: center;">
                                <span class="status-badge">${s.status}</span>
                            </td>
                        </tr>
                    `).join('')}
                </tbody>
            </table>

            <div class="footer">
                Gerado automaticamente pelo sistema PIPA VOICE AI.
            </div>
            <script>
                window.onload = function() { window.print(); }
            </script>
        </body>
        </html>
      `;

      printWindow.document.write(html);
      printWindow.document.close();
  };

  const updateStudentName = (id: number, newName: string) => {
    setStudents(students.map(s => s.id === id ? { ...s, name: newName } : s));
  };

