                            <td className="p-4"><input className={`font-bold uppercase outline-none bg-transparent w-full transition-colors ${isRecordingThis ? 'text-rose-700' : 'text-slate-700 focus:text-blue-600'}`} value={student.name} onChange={(e) => updateStudentName(student.id, e.target.value)} /></td>
                            <td className="p-4 text-center"><button onClick={(e) => { e.stopPropagation(); toggleRecording(student.id); }} disabled={activeStudentId !== null && !isRecordingThis} className={`p-2 rounded-full transition-all transform hover:scale-110 shadow-sm ${isRecordingThis ? 'bg-rose-500 text-white shadow-rose-200 animate-pulse' : 'bg-white border border-slate-200 text-slate-400 hover:text-blue-600 hover:border-blue-200'} ${activeStudentId !== null && !isRecordingThis ? 'opacity-30 cursor-not-allowed' : ''}`}>{isRecordingThis ? <Square className="w-4 h-4 fill-current" /> : <Mic className="w-4 h-4" />}</button></td>
                            <td className="p-4 text-center font-mono font-bold text-slate-600">{student.ppm}</td>
                            <td className="p-4 text-center">
                                <span className={`px-2 py-1 rounded-md text-[9px] font-black uppercase tracking-wide ${
                                    student.status === 'Nível 1' ? 'bg-red-100 text-red-700' :
                                    student.status === 'Nível 2' ? 'bg-red-100 text-red-700' :
                                    student.status === 'Nível 3' ? 'bg-orange-100 text-orange-700' :
                                    student.status === 'Nível 4' ? 'bg-amber-100 text-amber-700' :
                                    student.status === 'Iniciante' ? 'bg-blue-100 text-blue-700' : 'bg-emerald-100 text-emerald-700'
                                }`}>{student.status}</span>
                            </td>
                            <td className="p-4 text-center">
                                {student.report && (
                                    <button onClick={(e) => { e.stopPropagation(); handleViewStudentReport(student); }} className="p-1.5 rounded bg-blue-50 text-blue-600 hover:bg-blue-600 hover:text-white transition-colors" title="Ver Laudo Técnico">
                                        <FileText className="w-4 h-4" />
                                    </button>
                                )}
                            </td>
                            <td className="p-4 text-center"><button onClick={(e) => { e.stopPropagation(); removeStudent(student.id); }} className="text-slate-300 hover:text-rose-500 transition-colors"><Trash2 className="w-3 h-3" /></button></td>
                        </tr>
                        );
                    })}
                    {filteredStudents.length === 0 && (<tr><td colSpan={6} className="p-8 text-center text-slate-400 italic">Nenhum aluno nesta turma.</td></tr>)}
                    </tbody>
                </table>
                </div>
            </div>
            </div>

            {/* Right Column: Diagnostics & Charts */}
            <div className="lg:col-span-5 space-y-6">

            {/* Step Tabs */}
            <div className="flex gap-2 p-1 bg-slate-200 rounded-lg">
                {[{ id: 0, label: "1. PALAVRAS" }, { id: 1, label: "2. PSEUDOPALAVRAS" }, { id: 2, label: "3. TEXTO" }].map(step => (
                <button key={step.id} onClick={() => setCurrentStep(step.id as 0 | 1 | 2)} className={`flex-1 py-2 text-[10px] font-bold uppercase tracking-wider rounded-md transition-all ${currentStep === step.id ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}>{step.label}</button>
                ))}
            </div>

            {/* Live Diagnostic Panel */}
            <div className={`rounded-xl border-4 p-6 min-h-[400px] flex flex-col transition-all duration-300 relative overflow-hidden shadow-2xl ${recordingState === 'recording' ? 'bg-slate-900 border-rose-500' : 'bg-slate-900 border-slate-800'}`}>
                <div className="absolute inset-0 pointer-events-none bg-[linear-gradient(rgba(18,16,16,0)_50%,rgba(0,0,0,0.25)_50%),linear-gradient(90deg,rgba(255,0,0,0.06),rgba(0,255,0,0.02),rgba(0,0,255,0.06))] z-0 bg-[length:100%_2px,3px_100%]"></div>
                <div className="flex justify-between items-center mb-4 border-b border-slate-800 pb-4 relative z-10">
                <h2 className="text-blue-400 font-bold uppercase text-[10px] tracking-widest italic flex items-center gap-2"><Layers className="w-3 h-3" />{currentStep === 0 ? "Leitura de Palavras" : currentStep === 1 ? "Leitura de Pseudopalavras" : "Leitura de Texto"}</h2>
                <span className={`text-[9px] px-2 py-1 rounded font-bold uppercase tracking-wider ${recordingState === 'recording' ? 'bg-rose-600 text-white animate-pulse' : 'bg-slate-800 text-slate-500'}`}>{recordingState === 'recording' ? 'GRAVANDO' : recordingState === 'analyzing' ? 'PROCESSANDO' : 'VISUALIZANDO'}</span>
                </div>
                <div className="flex-grow font-mono text-xs leading-relaxed whitespace-pre-wrap relative z-10 overflow-y-auto max-h-64 custom-scrollbar">
                {viewStudentId ? (
                    <>
                    <span className="text-slate-500 block mb-2">{recordingState === 'recording' ? `// Gravando etapa ${currentStep + 1}...` : `// Conteúdo gravado (Etapa ${currentStep + 1}):`}</span>
                    <span className={recordingState === 'recording' ? "text-rose-400" : "text-emerald-400"}>{displayTranscript || <span className="text-slate-600 italic">Nenhum áudio gravado para esta etapa.</span>}</span>
                    {recordingState === 'recording' && <span className="animate-pulse inline-block w-2 h-4 bg-rose-500 ml-1 align-middle"></span>}
                    </>
                ) : (
                    <div className="h-full flex flex-col justify-center items-center text-slate-600 gap-2"><Mic className="w-8 h-8 opacity-20" /><p className="text-center">Selecione um aluno da lista<br/>para visualizar ou gravar.</p></div>
                )}
                </div>
                <div className="mt-auto grid grid-cols-3 gap-2 border-t border-slate-800 pt-4 text-center relative z-10">
                <div className="bg-slate-800/50 rounded p-2"><span className="block text-[8px] text-slate-500 uppercase tracking-wider mb-1">Tempo</span><span className={`font-bold text-lg font-mono ${recordingState === 'recording' && liveMetrics.time >= 55 ? 'text-red-500 animate-pulse' : 'text-white'}`}>{recordingState === 'recording' ? liveMetrics.time : 0}s</span></div>
                <div className="bg-slate-800/50 rounded p-2"><span className="block text-[8px] text-slate-500 uppercase tracking-wider mb-1">Palavras</span><span className="text-white font-bold text-lg font-mono">{recordingState === 'recording' ? liveMetrics.words : 0}</span></div>
                <div className="bg-slate-800/50 rounded p-2 border border-slate-700"><span className="block text-[8px] text-slate-500 uppercase tracking-wider mb-1">PPM Atual</span><span className={`font-bold text-lg font-mono ${liveMetrics.ppm > 60 ? 'text-emerald-400' : 'text-blue-400'}`}>{recordingState === 'recording' ? liveMetrics.ppm : (currentStudent?.ppm || 0)}</span></div>
                </div>
            </div>

            <button onClick={triggerAnalysis} disabled={!viewStudentId || recordingState !== 'idle'} className={`w-full py-4 rounded-xl font-black uppercase tracking-widest text-sm flex items-center justify-center gap-2 shadow-lg transition-all ${!viewStudentId || recordingState !== 'idle' ? 'bg-slate-200 text-slate-400 cursor-not-allowed' : 'bg-emerald-500 text-white hover:bg-emerald-600 shadow-emerald-200 hover:scale-[1.02]'}`}><Zap className="w-5 h-5 fill-current" /> Gerar Diagnóstico CAED</button>

            {/* Last Report View (Simplified here as modal exists) */}
            {currentStudent?.report && (
                <div className="bg-white rounded-xl shadow-sm border border-slate-100 p-6 flex flex-col items-center text-center">
                    <h3 className="text-xs font-black uppercase text-slate-500 tracking-widest mb-2">Diagnóstico Recente</h3>
                    <p className="text-xs text-slate-500 mb-4">O último diagnóstico gerado para {currentStudent.name} está disponível.</p>
                    <button onClick={() => handleViewStudentReport(currentStudent)} className="text-xs font-bold text-blue-600 uppercase border border-blue-200 px-4 py-2 rounded-lg hover:bg-blue-50">Abrir Laudo Completo</button>
                </div>
            )}

            {/* Chart Section */}
            <div className="bg-white rounded-xl shadow-sm border border-slate-100 p-6">
                <h3 className="text-xs font-black uppercase text-slate-500 tracking-widest mb-6 text-center">Distribuição de Fluência ({currentClass})</h3>
                <FluencyChart students={filteredStudents} />
            </div>

            </div>
        </main>
      )}

      {/* Footer */}
      <footer className="bg-slate-100 py-6 mt-auto border-t border-slate-200">
          <div className="container mx-auto px-6 text-center">
              <p className="text-xs text-slate-500 font-medium tracking-wide">
                  PIPA Voice AI: Tecnologia a serviço da equidade e da redução de desigualdades na alfabetização.
              </p>
          </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useMemo, useState } from 'react';
import { Student, FluencyLevel } from '../types';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip as RechartsTooltip, 
  ResponsiveContainer, PieChart, Pie, Cell, Legend 
} from 'recharts';
import { ArrowLeft, Users, Zap, Target, Award, TrendingUp, Info, X, Download, AlertOctagon, FileDown } from 'lucide-react';

interface DashboardProps {
  students: Student[]; // Contains ONLY current class students for charts
  allStudents: Student[]; // Contains ALL students for CSV export
  currentClass: string;
  schoolName: string;
  onBack: () => void;
}

// Color Palette Definition
const COLORS: Record<FluencyLevel, string> = {
  'Nível 1': '#ef4444', // Red-500
  'Nível 2': '#dc2626', // Red-600
  'Nível 3': '#f97316', // Orange-500
  'Nível 4': '#f59e0b', // Amber-500
  'Iniciante': '#3b82f6', // Blue-500
  'Fluente': '#10b981', // Emerald-500
};

const LEGEND_DATA = [
  { level: 'Nível 1', desc: 'Pré-leitor: Não decodifica palavras isoladas. Dificuldade severa.', color: 'bg-red-500' },
  { level: 'Nível 2', desc: 'Leitor de Palavras: Lê palavras isoladas com muitos erros. Silabação excessiva.', color: 'bg-red-600' },
  { level: 'Nível 3', desc: 'Em Construção: Lê palavras simples corretamente, trava em complexas.', color: 'bg-orange-500' },
  { level: 'Nível 4', desc: 'Fraseado: Lê frases curtas, ainda com silabação, mas compreende o sentido básico.', color: 'bg-amber-500' },
  { level: 'Iniciante', desc: 'Transição: Lê textos curtos com baixa fluência. Início da automação.', color: 'bg-blue-500' },
  { level: 'Fluente', desc: 'Consolidado: Leitura rítmica, precisa, respeita pontuação e entonação.', color: 'bg-emerald-500' },
];

const Dashboard: React.FC<DashboardProps> = ({ students, allStudents, currentClass, schoolName, onBack }) => {
  const [isLegendOpen, setIsLegendOpen] = useState(false);

  // --- Data Processing ---
  const stats = useMemo(() => {
    const evaluated = students.filter(s => s.ppm > 0);
    const totalEvaluated = evaluated.length;

    // Critical students (Global - Network View)
    const criticalStudents = allStudents.filter(s => s.status === 'Nível 1' || s.status === 'Nível 2');
    const criticalCount = criticalStudents.length;

    // School IFL Calculation (Network View - Weighted Index 0-10)
    // Formula: (N1*0 + N2*1 + N3*2.5 + N4*4 + Ini*6 + Flu*10) / Total
    const allEvaluated = allStudents.filter(s => s.ppm > 0);
    let schoolIFL = 0;

    if (allEvaluated.length > 0) {
        const weights: Record<string, number> = {
            'Nível 1': 0,
            'Nível 2': 1,
            'Nível 3': 2.5,
            'Nível 4': 4,
            'Iniciante': 6,
            'Fluente': 10
        };

        const totalScore = allEvaluated.reduce((acc, s) => {
            return acc + (weights[s.status] || 0);
        }, 0);

        schoolIFL = totalScore / allEvaluated.length;
    }

    const emptyLevels: Record<FluencyLevel, number> = {
      'Nível 1': 0, 'Nível 2': 0, 'Nível 3': 0, 'Nível 4': 0, 'Iniciante': 0, 'Fluente': 0
    };

    if (totalEvaluated === 0) return {
        totalEvaluated: 0, avgPpm: 0, avgAccuracy: 0, levels: emptyLevels, classLevel: "", evaluated: [], mode: "Nível 1" as FluencyLevel, criticalStudents, criticalCount, schoolIFL
    };

    const totalPpm = evaluated.reduce((acc, s) => acc + s.ppm, 0);
    const avgPpm = Math.round(totalPpm / totalEvaluated);

    // Heuristic for Accuracy
    const calculateAccuracy = (ppm: number) => Math.min(100, Math.max(60, 70 + (ppm * 0.3)));
    const avgAccuracy = Math.round(
      evaluated.reduce((acc, s) => acc + calculateAccuracy(s.ppm), 0) / totalEvaluated
    );

    // Classification Counts
    const levels = { ...emptyLevels };

    evaluated.forEach(s => {
      if (levels[s.status] !== undefined) {
        levels[s.status]++;
      } else {
        levels['Nível 1']++;
      }
    });

    // Determine Class Level
    let classLevel = "EM DESENVOLVIMENTO";
    if (levels['Fluente'] > totalEvaluated * 0.5) classLevel = "TURMA FLUENTE";
    else if ((levels['Nível 1'] + levels['Nível 2']) > totalEvaluated * 0.4) classLevel = "ATENÇÃO PRIORITÁRIA";

    const mode = (Object.keys(levels) as FluencyLevel[]).reduce((a, b) => levels[a] > levels[b] ? a : b);

    return {
      totalEvaluated,
      avgPpm,
      avgAccuracy,
      levels,
      classLevel,
      evaluated,
      mode,
      criticalStudents,
      criticalCount,
      schoolIFL
    };
  }, [students, allStudents]);

  // --- Chart Data Helpers ---
  const pieData = stats && stats.totalEvaluated > 0 ? Object.entries(stats.levels).map(([name, value]) => ({
    name,
    value,
    color: COLORS[name as FluencyLevel]
  })).filter(d => d.value > 0) : [];

  const barData = stats && stats.totalEvaluated > 0 ? [
    { name: 'Palavras', score: Math.min(100, stats.avgAccuracy + 5) },
    { name: 'Pseudopalavras', score: Math.min(100, stats.avgAccuracy - 10) },
    { name: 'Texto (PPM)', score: stats.avgPpm }, 
  ] : [];

  // --- CSV Export Handler (School Wide) ---
  const handleExport = () => {
    const evaluatedAll = allStudents.filter(s => s.ppm > 0);
    if (evaluatedAll.length === 0) return alert("Não há dados avaliados para exportar.");

    const headers = ["Nome do Aluno", "Turma", "PPM", "Nível Fluência", "Pseudopalavras (Transcrição)", "Erros Estimados (Pseudo)"];

    const rows = evaluatedAll.map(s => {
      let errorsEst = "Baixo";
      if (s.status === 'Nível 1' || s.status === 'Nível 2') errorsEst = "Crítico";
      else if (s.status === 'Nível 3' || s.status === 'Nível 4') errorsEst = "Moderado";

      return [
        `"${s.name}"`,
        `"${s.turma}"`,
        s.ppm,
        `"${s.status}"`,
        `"${s.steps[1].replace(/"/g, '""')}"`, 
        `"${errorsEst}"`
      ].join(",");
    });

    const csvContent = "data:text/csv;charset=utf-8," + [headers.join(","), ...rows].join("\n");
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    const date = new Date().toISOString().split('T')[0];
    link.setAttribute("download", `Dados_Escolares_Completo_${date}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // --- Critical List Export ---
  const handleExportCritical = () => {
      if (stats.criticalCount === 0) return alert("Não há alunos em estado crítico para exportar.");

      const headers = ["Nome do Aluno", "Escola", "Turma", "Nível de Fluência", "Status"];
      const rows = stats.criticalStudents.map(s => {
          return `"${s.name}","${schoolName || 'Não Informada'}","${s.turma}","${s.status}","Intervenção Imediata"`;
      });

      const csvContent = "data:text/csv;charset=utf-8," + [headers.join(","), ...rows].join("\n");
      const encodedUri = encodeURI(csvContent);
      const link = document.createElement("a");
      link.setAttribute("href", encodedUri);
      const date = new Date().toISOString().split('T')[0];
      link.setAttribute("download", `Lista_Intervencao_Prioritaria_${date}.csv`);
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
  };

  // --- Empty State ---
  if (!stats || (stats.totalEvaluated === 0 && stats.criticalCount === 0)) {
    return (
      <div className="flex flex-col items-center justify-center h-[60vh] text-slate-400">
        <Users className="w-16 h-16 mb-4 opacity-20" />
        <h2 className="text-xl font-bold uppercase tracking-widest">Sem dados para análise</h2>
        <p className="text-sm mt-2">Realize coletas na turma {currentClass} para gerar o dashboard.</p>
        <button onClick={onBack} className="mt-6 px-6 py-2 bg-blue-600 text-white rounded-lg font-bold hover:bg-blue-700 transition-all">
          Voltar para Coleta
        </button>
      </div>
    );
  }

  // Determine Priority Status for School
  // Using the new formula logic for IFL <= 6.0
  const isPrioritySchool = stats.schoolIFL <= 6.0 && allStudents.filter(s => s.ppm > 0).length > 0;

  return (
    <div className="animate-in fade-in slide-in-from-bottom-4 duration-500 relative pb-12">

      {/* Legend Modal */}
      {isLegendOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 backdrop-blur-sm p-4" onClick={() => setIsLegendOpen(false)}>
           <div className="bg-white rounded-2xl shadow-2xl max-w-lg w-full overflow-hidden border border-slate-100" onClick={e => e.stopPropagation()}>
              <div className="bg-slate-50 p-4 border-b border-slate-100 flex justify-between items-center">
                 <h3 className="font-black text-slate-700 uppercase tracking-widest text-sm flex items-center gap-2">
                    <Info className="w-4 h-4 text-blue-500" /> Matriz de Fluência
                 </h3>
                 <button onClick={() => setIsLegendOpen(false)} className="text-slate-400 hover:text-slate-600"><X className="w-5 h-5" /></button>
              </div>
              <div className="p-6 space-y-4">
                 {LEGEND_DATA.map((item) => (
                    <div key={item.level} className="flex gap-4 items-start">
                       <div className={`w-3 h-3 rounded-full mt-1.5 shrink-0 ${item.color}`}></div>
                       <div>
                          <p className="font-bold text-xs uppercase text-slate-800">{item.level}</p>
                          <p className="text-xs text-slate-500 leading-relaxed">{item.desc}</p>
                       </div>
                    </div>
                 ))}
              </div>
              <div className="bg-slate-50 p-4 text-center">
                 <button onClick={() => setIsLegendOpen(false)} className="text-xs font-bold text-blue-600 uppercase tracking-wider hover:underline">Fechar Legenda</button>
              </div>
           </div>
        </div>
      )}

      {/* Network Alert Header */}
      <div className="bg-rose-50 border border-rose-100 rounded-xl p-4 mb-8 flex items-center justify-between shadow-sm">
          <div className="flex items-center gap-3">
              <div className="w-10 h-10 bg-rose-100 rounded-full flex items-center justify-center">
                  <AlertOctagon className="w-5 h-5 text-rose-600" />
              </div>
              <div>
                  <h2 className="text-sm font-black uppercase text-rose-700 tracking-wide">Alerta de Rede</h2>
                  <p className="text-xs text-rose-600 font-medium">Total de alunos em estado crítico na rede: <span className="font-bold text-lg ml-1">{stats.criticalCount}</span> alunos</p>
                  <p className="text-[10px] text-slate-400 uppercase mt-1">IFL Calculado: {stats.schoolIFL.toFixed(2)} / 10.0</p>
              </div>
          </div>
          {isPrioritySchool && (
              <span className="px-3 py-1 bg-red-600 text-white text-[10px] font-black uppercase tracking-widest rounded-full animate-pulse shadow-lg shadow-red-200">
                  ⚠️ Unidade Prioritária (IFL ≤ 6.0)
              </span>
          )}
      </div>

      {/* Header / Nav */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-8">
        <div>
           <button 
             onClick={onBack}
             className="flex items-center gap-2 text-slate-500 hover:text-blue-600 transition-colors font-bold uppercase text-xs tracking-wider mb-2"
           >
             <ArrowLeft className="w-4 h-4" /> Voltar à Coleta
           </button>
           <div className="flex flex-col md:flex-row md:items-center gap-3">
             <h1 className="text-2xl font-black text-slate-800 uppercase tracking-tight">
               Gestão de Rede <span className="text-blue-600">:: {schoolName || "Geral"}</span>
             </h1>
             <button 
               onClick={() => setIsLegendOpen(true)}
               className="p-1.5 rounded-full bg-slate-100 text-slate-500 hover:bg-blue-100 hover:text-blue-600 transition-colors self-start md:self-auto"
               title="Ver Legenda Técnica"
             >
               <Info className="w-4 h-4" />
             </button>
           </div>
        </div>

        <div className="flex items-center gap-4">
           <button 
             onClick={handleExport}
             className="flex items-center gap-2 bg-slate-800 text-white px-4 py-2 rounded-lg text-xs font-bold uppercase tracking-wide hover:bg-slate-700 transition-all shadow-lg shadow-slate-200"
           >
             <Download className="w-4 h-4" /> Exportar Tudo (CSV)
           </button>
           <div className="text-right hidden md:block">
              <span className="block text-[10px] font-bold text-slate-400 uppercase tracking-widest">Classificação da Turma Atual</span>
              <span className={`text-lg font-black uppercase ${
                  stats.classLevel === 'TURMA FLUENTE' ? 'text-emerald-500' : 
                  stats.classLevel === 'ATENÇÃO PRIORITÁRIA' ? 'text-rose-500' : 'text-amber-500'
              }`}>
                {stats.classLevel}
              </span>
           </div>
        </div>
      </div>

      {/* KPI Cards (Current Class View) */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-8">
        <div className="bg-white p-5 rounded-xl shadow-sm border border-slate-100 flex flex-col justify-between relative overflow-hidden group">
            <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:scale-110 transition-transform"><Zap className="w-12 h-12 text-blue-600" /></div>
            <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Média PPM (Turma)</span>
            <span className="text-3xl font-black text-slate-800 mt-2">{stats.avgPpm}</span>
            <div className="w-full bg-slate-100 h-1 mt-4 rounded-full overflow-hidden">
                <div className="bg-blue-500 h-full" style={{ width: `${Math.min(100, stats.avgPpm)}%` }}></div>
            </div>
        </div>

        <div className="bg-white p-5 rounded-xl shadow-sm border border-slate-100 flex flex-col justify-between relative overflow-hidden group">
            <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:scale-110 transition-transform"><Target className="w-12 h-12 text-emerald-600" /></div>
            <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Precisão Est.</span>
            <span className="text-3xl font-black text-slate-800 mt-2">{stats.avgAccuracy}%</span>
            <div className="w-full bg-slate-100 h-1 mt-4 rounded-full overflow-hidden">
                <div className="bg-emerald-500 h-full" style={{ width: `${stats.avgAccuracy}%` }}></div>
            </div>
        </div>

        <div className="bg-white p-5 rounded-xl shadow-sm border border-slate-100 flex flex-col justify-between relative overflow-hidden group">
            <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:scale-110 transition-transform"><Users className="w-12 h-12 text-violet-600" /></div>
            <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Alunos Avaliados</span>
            <span className="text-3xl font-black text-slate-800 mt-2">{stats.totalEvaluated}</span>
            <span className="text-[10px] text-slate-400 font-bold mt-4 block">De {students.length} matriculados</span>
