import Dashboard from './components/Dashboard';
import { Plus, Mic, Square, Activity, Save, Trash2, BookOpen, Layers, Zap, Download, Users, AlertTriangle, PlusCircle, BarChart3, FileText, Printer, X, Building2, Map } from 'lucide-react';

