               <div className="bg-slate-50 p-4 text-center border-t border-slate-200">
                    <button onClick={() => setIsStudentReportModalOpen(false)} className="text-xs font-bold text-blue-600 uppercase">Fechar</button>
               </div>
           </div>
        </div>
