      let newStatus: any = 'Nível 1';
      if (result.includes("Nível 2")) newStatus = "Nível 2";
      else if (result.includes("Nível 3")) newStatus = "Nível 3";
      else if (result.includes("Nível 4")) newStatus = "Nível 4";
      else if (result.includes("Iniciante")) newStatus = "Iniciante";
      else if (result.includes("Fluente")) newStatus = "Fluente";
      else if (student.ppm > 90) newStatus = "Fluente"; // Fallback heuristics
      else if (student.ppm > 70) newStatus = "Iniciante";
      else if (student.ppm > 50) newStatus = "Nível 4";
      else if (student.ppm > 30) newStatus = "Nível 3";
      else if (student.ppm > 10) newStatus = "Nível 2";

      setStudents(prev => prev.map(s => {
          if (s.id === viewStudentId) {
